INSERT INTO `wp_aioseo_notifications` VALUES (1,'69cd86326eed9',NULL,'Search Engines Blocked','Warning: AIOSEO has detected that you are blocking access to search engines. You can change this in Settings > Reading if this was unintended.','error','[\"all\"]',NULL,'blog-visibility','2026-04-01 20:55:14',NULL,'Fix Now','http://localhost/wordpress/wp-admin/options-reading.php','Remind Me Later','http://action#notification/blog-visibility-reminder',0,0,'2026-04-01 20:55:14','2026-04-01 20:55:14'),(2,'69cd86328859a',NULL,'Have you connected your site to Google Search Console?','AIOSEO can now verify whether your site is correctly verified with Google Search Console and that your sitemaps have been submitted correctly. Connect with Google Search Console now to ensure your content is being added to Google as soon as possible for increased rankings.','warning','[\"all\"]',NULL,'search-console-site-not-connected','2026-04-01 20:55:14',NULL,'Connect to Google Search Console','https://route#aioseo-settings&aioseo-scroll=google-search-console-settings&aioseo-highlight=google-search-console-settings:webmaster-tools?activetool=googleSearchConsole',NULL,NULL,0,0,'2026-04-01 20:55:14','2026-04-01 20:55:14'),(3,'6a1ec6f042d12',NULL,'NEW in 4.9.6: AI Schema Generator + Bulk SEO Tools','<p>We just released one of our most ambitious updates yet, and one of them is available to Lite users, too!</p>\n\n<p><strong>🤖 AI Schema Generator: </strong>Add structured data to any page without writing code. Smart Schema analyzes your content and writes schema for you. Or use a prompt to tell it the schema type you want. No technical background or JSON-LD required. <em>(Available to Pro users)</em></p>\n\n<p><strong>✅ AI Bulk Actions: </strong>Generate SEO titles, meta descriptions, and image alt text across your whole site in one go. <em>(All users, including Lite, with AI credits)</em></p>\n\n<p><strong>✍️ Notes Field in Redirects: </strong>Add a comment to any redirect so you always know why it\'s there. <em>(Pro)</em></p>\n\n<p>Update to 4.9.6 and try the new AI tools today! Your workflow will be better for it.</p>','success','[\"4-x\",\"lite\"]',1415,NULL,'2026-04-22 00:00:00',NULL,'Learn More','https://aioseo.com/aioseo-4-9-6-release/?utm_source=WordPress&utm_medium=plugin-notification&utm_campaign=4-9-6-announcement-v4-x-lite','Get AIOSEO Pro','https://aioseo.com/lite-upgrade/?utm_source=WordPress&utm_medium=plugin-notification&utm_campaign=4-9-6-announcement-v4-x-lite',0,0,'2026-06-02 12:05:04','2026-06-02 12:05:04'),(4,'6a1ec6f3787e5',NULL,'Email Reports','Stay ahead in SEO with our new email digest! Get the latest tips, trends, and tools delivered right to your inbox, helping you optimize smarter and faster. Enable it today and never miss an update that can take your rankings to the next level.','info','[\"all\"]',NULL,'email-reports-enable-reminder','2026-06-02 12:05:07',NULL,'Enable Email Reports','https://route#aioseo-settings&aioseo-scroll=aioseo-email-summary-row&aioseo-highlight=aioseo-email-summary-row:advanced','All Good, I\'m already getting it','http://action#notification/email-reports-enable',0,0,'2026-06-02 12:05:07','2026-06-02 12:05:07'),(5,'6a2fb33721b75',NULL,'19 Years. 3M+ Installs. Here\'s What We\'ve Learned.','<img src=\"data:image/webp;base64,\" alt=\"\" class=\"wp-image-1443\"/>\n\n<p>Most ranking problems aren\'t about content. They\'re about signals Google can\'t read — missing schema, weak internal links, orphaned pages that get crawled but never ranked. <strong>Fix those, and rankings follow.</strong></p>\n\n<p><strong>🎉</strong> <strong>It\'s our birthday this week, and we’re celebrating with a sale. 🎉</strong> </p>\n\n<p>Every plan (and upgrade!) is up to 60% off through June 24. This is <em>the</em> best time of year to get the tools that find and fix exactly those problems. Plans from $49.50.</p>\n\n<p>14-day money-back guarantee. Sale ends June 24 at 11:59 PM EST.</p>','success','[\"4-x\",\"lite\"]',1445,NULL,'2026-06-18 00:00:00','2026-06-25 00:00:00','Get the Birthday Deal','https://aioseo.com/pricing/?utm_source=WordPress&utm_medium=plugin-notification&utm_campaign=birthday-sale-2026-v4-x-lite',NULL,NULL,0,0,'2026-06-15 08:09:27','2026-06-15 08:09:27');
/*!40000 ALTER TABLE `wp_aioseo_notifications` ENABLE KEYS */;
