nt\";s:2:\"no\";}'),(1156,1046,'_video','a:0:{}'),(1157,1046,'_tutor_enable_qa','no'),(1158,1046,'_tutor_is_public_course','no'),(1159,1046,'tutor_course_sale_price','0'),(1160,1046,'_course_duration','a:2:{s:5:\"hours\";s:1:\"0\";s:7:\"minutes\";s:1:\"0\";}'),(1161,1046,'_tutor_course_level','intermediate'),(1162,1047,'_edit_lock','1781527098:1'),(1163,1049,'_edit_lock','1781527653:1'),(1164,1050,'_edit_lock','1781527852:1'),(1165,1051,'_edit_lock','1781527830:1'),(1166,1052,'_edit_lock','1781624964:1'),(1167,1055,'_menu_item_type','post_type'),(1168,1055,'_menu_item_menu_item_parent','0'),(1169,1055,'_menu_item_object_id','1052'),(1170,1055,'_menu_item_object','page'),(1171,1055,'_menu_item_target',''),(1172,1055,'_menu_item_classes','a:1:{i:0;s:0:\"\";}'),(1173,1055,'_menu_item_xfn',''),(1174,1055,'_menu_item_url',''),(1176,1056,'_menu_item_type','post_type'),(1177,1056,'_menu_item_menu_item_parent','0'),(1178,1056,'_menu_item_object_id','968'),(1179,1056,'_menu_item_object','page'),(1180,1056,'_menu_item_target',''),(1181,1056,'_menu_item_classes','a:1:{i:0;s:0:\"\";}'),(1182,1056,'_menu_item_xfn',''),(1183,1056,'_menu_item_url',''),(1185,965,'_tutor_course_started','1781528409'),(1186,1030,'wpforms_entries_count','3'),(1187,1058,'_tutorstarter_schema','a:32:{s:18:\"main_schema_select\";s:0:\"\";s:17:\"sub_schema_select\";s:0:\"\";s:4:\"name\";s:0:\"\";s:8:\"logo_url\";s:0:\"\";s:11:\"description\";s:4348:\"Tujuan PembelajaranSetelah mengikuti pembelajaran ini, mahasiswa diharapkan mampu:Memahami latar belakang lahirnya Pancasila.Menjelaskan proses perumusan Pancasila.Mengetahui peran tokoh-tokoh dalam perumusan Pancasila.Memahami pentingnya Pancasila sebagai dasar negara Indonesia.Menghargai perjuangan para pendiri bangsa dalam merumuskan dasar negara. PendahuluanPancasila merupakan dasar negara Republik Indonesia yang menjadi pedoman dalam kehidupan berbangsa dan bernegara. Pancasila tidak lahir secara tiba-tiba, melainkan melalui proses panjang yang melibatkan pemikiran, diskusi, dan perjuangan para tokoh bangsa. Oleh karena itu, memahami sejarah lahirnya Pancasila sangat penting agar masyarakat Indonesia mampu menghargai nilai-nilai yang terkandung di dalamnya.Sebagai dasar negara, Pancasila menjadi landasan bagi seluruh peraturan dan kebijakan yang berlaku di Indonesia. Selain itu, Pancasila juga berfungsi sebagai ideologi bangsa yang mampu mempersatukan masyarakat Indonesia yang memiliki beragam suku, agama, budaya, dan bahasa. Latar Belakang Lahirnya PancasilaPada masa penjajahan, bangsa Indonesia mengalami penderitaan yang cukup panjang akibat kekuasaan bangsa asing. Kondisi tersebut mendorong munculnya semangat persatuan dan perjuangan untuk memperoleh kemerdekaan.Menjelang berakhirnya Perang Dunia II, Jepang yang saat itu menduduki Indonesia mulai mengalami kekalahan. Untuk menarik simpati rakyat Indonesia, Jepang membentuk Badan Penyelidik Usaha-Usaha Persiapan Kemerdekaan Indonesia (BPUPKI) pada tanggal 29 April 1945.BPUPKI bertugas mempersiapkan berbagai hal yang berkaitan dengan kemerdekaan Indonesia, termasuk merumuskan dasar negara yang akan digunakan setelah Indonesia merdeka. Sidang BPUPKISidang pertama BPUPKI dilaksanakan pada tanggal 29 Mei sampai 1 Juni 1945. Dalam sidang tersebut, para tokoh bangsa menyampaikan gagasannya mengenai dasar negara Indonesia.Beberapa tokoh yang menyampaikan usulan antara lain:Muhammad YaminMuhammad Yamin mengusulkan lima asas dasar negara, yaitu:Peri KebangsaanPeri KemanusiaanPeri KetuhananPeri KerakyatanKesejahteraan RakyatUsulan tersebut menekankan pentingnya persatuan bangsa dan kesejahteraan masyarakat.SoepomoSoepomo mengemukakan konsep negara integralistik yang menekankan persatuan seluruh rakyat Indonesia. Menurutnya, negara harus mampu menyatukan seluruh golongan dan mengutamakan kepentingan bersama.Ir. SoekarnoPada tanggal 1 Juni 1945, Ir. Soekarno menyampaikan pidato yang berisi lima prinsip dasar negara, yaitu:Kebangsaan IndonesiaInternasionalisme atau PerikemanusiaanMufakat atau DemokrasiKesejahteraan SosialKetuhanan Yang Maha EsaLima prinsip tersebut kemudian diberi nama Pancasila. Oleh karena itu, tanggal 1 Juni diperingati sebagai Hari Lahir Pancasila. Peran Panitia SembilanSetelah sidang BPUPKI, dibentuk Panitia Sembilan yang bertugas merumuskan dasar negara berdasarkan berbagai usulan yang telah disampaikan.Panitia Sembilan terdiri dari:Ir. SoekarnoMohammad HattaMuhammad YaminAhmad SubardjoAbdul Kahar MuzakirAbikusno TjokrosujosoAgus SalimWahid HasyimA.A. MaramisPada tanggal 22 Juni 1945, Panitia Sembilan berhasil menyusun sebuah dokumen yang dikenal sebagai Piagam Jakarta. Dokumen ini menjadi dasar penting dalam perumusan Pancasila. Penetapan PancasilaSetelah Indonesia memproklamasikan kemerdekaan pada tanggal 17 Agustus 1945, Panitia Persiapan Kemerdekaan Indonesia (PPKI) mengadakan sidang pada tanggal 18 Agustus 1945.Dalam sidang tersebut, disepakati rumusan final Pancasila yang tercantum dalam Pembukaan Undang-Undang Dasar 1945, yaitu:Ketuhanan Yang Maha EsaKemanusiaan yang Adil dan BeradabPersatuan IndonesiaKerakyatan yang Dipimpin oleh Hikmat Kebijaksanaan dalam Permusyawaratan/PerwakilanKeadilan Sosial bagi Seluruh Rakyat IndonesiaRumusan tersebut kemudian ditetapkan sebagai dasar negara Republik Indonesia dan tetap digunakan hingga saat ini. Makna Sejarah Lahirnya PancasilaProses lahirnya Pancasila memberikan banyak pelajaran penting bagi bangsa Indonesia.Beberapa nilai yang dapat dipetik antara lain:Semangat persatuan dan kesatuan.Pentingnya musyawarah dalam mengambil keputusan.Menghargai perbedaan pendapat.Mengutamakan kepentingan bangsa di atas kepentingan pribadi.Menjaga kerukunan dalam keberagaman.Nilai-nilai tersebut masih sangat relevan dalam kehidupan masyarakat Indonesia saat ini.\";s:7:\"address\";s:0:\"\";s:5:\"phone\";s:0:\"\";s:4:\"city\";s:0:\"\";s:5:\"email\";s:0:\"\";s:12:\"state_region\";s:0:\"\";s:8:\"zip_code\";s:0:\"\";s:7:\"country\";s:0:\"\";s:6:\"po_box\";s:0:\"\";s:9:\"job_title\";s:0:\