orderRadius\\\":\\\"3\\\",\\\"fieldBorderSize\\\":\\\"1\\\",\\\"fieldBackgroundColor\\\":\\\"#ffffff\\\",\\\"fieldBorderColor\\\":\\\"rgba(0, 0, 0, 0.25)\\\",\\\"fieldTextColor\\\":\\\"rgba(0, 0, 0, 0.7)\\\",\\\"fieldMenuColor\\\":\\\"#ffffff\\\",\\\"pageBreakColor\\\":\\\"#066aab\\\",\\\"labelSize\\\":\\\"medium\\\",\\\"labelColor\\\":\\\"rgba(0, 0, 0, 0.85)\\\",\\\"labelSublabelColor\\\":\\\"rgba(0, 0, 0, 0.55)\\\",\\\"labelErrorColor\\\":\\\"#d63637\\\",\\\"buttonSize\\\":\\\"medium\\\",\\\"buttonBorderStyle\\\":\\\"none\\\",\\\"buttonBorderSize\\\":\\\"1\\\",\\\"buttonBorderRadius\\\":\\\"3\\\",\\\"buttonBackgroundColor\\\":\\\"#066aab\\\",\\\"buttonBorderColor\\\":\\\"#066aab\\\",\\\"buttonTextColor\\\":\\\"#ffffff\\\",\\\"backgroundColor\\\":\\\"rgba(0, 0, 0, 0)\\\",\\\"backgroundPosition\\\":\\\"center center\\\",\\\"backgroundUrl\\\":\\\"url()\\\",\\\"backgroundRepeat\\\":\\\"no-repeat\\\",\\\"backgroundSize\\\":\\\"cover\\\",\\\"backgroundSizeMode\\\":\\\"cover\\\",\\\"backgroundWidth\\\":\\\"100\\\",\\\"backgroundHeight\\\":\\\"100\\\",\\\"backgroundImage\\\":\\\"none\\\"}\"},\"form_title\":\"Presensi Mata Kuliah\",\"form_desc\":\"Masukkan Nama, Nim, Matkul dan Pertemuan\",\"submit_text\":\"Submit\",\"submit_text_processing\":\"Sending...\",\"form_class\":\"\",\"submit_class\":\"\",\"ajax_submit\":\"1\",\"notification_enable\":\"1\",\"notifications\":{\"1\":{\"email\":\"{admin_email}\",\"subject\":\"New Blank Form Entry\",\"sender_name\":\"Badali\",\"sender_address\":\"{admin_email}\",\"replyto\":\"\",\"message\":\"{all_fields}\",\"template\":\"\"}},\"confirmations\":{\"1\":{\"type\":\"message\",\"message\":\"<p>Thanks for contacting us! We will be in touch with you shortly.<\\/p>\",\"message_scroll\":\"1\",\"page\":\"previous_page\",\"page_url_parameters\":\"\",\"redirect\":\"\"}},\"antispam_v3\":\"1\",\"anti_spam\":{\"time_limit\":{\"enable\":\"1\",\"duration\":\"2\"},\"filtering_store_spam\":\"1\"},\"form_tags\":[],\"store_spam_entries\":\"0\"},\"search_terms\":\"\",\"providers\":{\"constant-contact-v3\":[]},\"meta\":{\"template\":\"blank\"}}','Presensi Mata Kuliah','Masukkan Nama, Nim, Matkul dan Pertemuan','inherit','closed','closed','','1030-revision-v1','','','2026-06-16 11:21:33','2026-06-16 11:21:33','',1030,'http://localhost/wordpress/?p=1197',0,'revision','',0),(1198,1,'2026-06-16 11:21:56','2026-06-16 11:21:56','','Pertemuan 7','','publish','closed','closed','','pertemuan-7-2','','','2026-06-16 11:21:56','2026-06-16 11:21:56','',1009,'http://localhost/wordpress/topics/pertemuan-7-2/',7,'topics','',0),(1199,1,'2026-06-16 11:23:00','2026-06-16 11:23:00','<h2 data-section-id=\"lnz3v4\" data-start=\"50\" data-end=\"72\">Tujuan Pembelajaran</h2><p data-start=\"73\" data-end=\"136\">Setelah mengikuti pembelajaran ini, mahasiswa diharapkan mampu:</p><ol data-start=\"138\" data-end=\"381\"><li data-section-id=\"1iu0yes\" data-start=\"138\" data-end=\"194\"><p data-start=\"140\" data-end=\"194\">Memahami pengertian Pancasila sebagai ideologi bangsa.</p></li><li data-section-id=\"jtb1li\" data-start=\"195\" data-end=\"252\"><p data-start=\"197\" data-end=\"252\">Menjelaskan fungsi Pancasila dalam kehidupan berbangsa.</p></li><li data-section-id=\"1u40n89\" data-start=\"253\" data-end=\"323\"><p data-start=\"255\" data-end=\"323\">Mengetahui pentingnya Pancasila dalam menghadapi perkembangan zaman.</p></li><li data-section-id=\"1szg8d0\" data-start=\"324\" data-end=\"381\"><p data-start=\"326\" data-end=\"381\">Menerapkan nilai Pancasila dalam kehidupan sehari-hari.</p></li></ol><h2 data-section-id=\"y1xlc\" data-start=\"383\" data-end=\"397\"> </h2><h2 data-section-id=\"y1xlc\" data-start=\"383\" data-end=\"397\">Pendahuluan</h2><p data-start=\"398\" data-end=\"589\">Pancasila bukan hanya dasar negara, tetapi juga merupakan ideologi bangsa Indonesia. Ideologi berarti kumpulan nilai, gagasan, dan cita-cita yang menjadi pedoman dalam kehidupan suatu bangsa.</p><p data-start=\"591\" data-end=\"827\">Sebagai ideologi bangsa, Pancasila menjadi arah bagi masyarakat Indonesia dalam bersikap dan bertindak. Nilai-nilai Pancasila membantu bangsa Indonesia menjaga persatuan, menghormati perbedaan, serta menghadapi berbagai tantangan zaman.</p><h2 data-section-id=\"tcw5tq\" data-start=\"829\" data-end=\"876\"> </h2><h2 data-section-id=\"tcw5tq\" data-start=\"829\" data-end=\"876\">Pengertian Pancasila sebagai Ideologi Bangsa</h2><p data-start=\"877\" data-end=\"1101\">Pancasila sebagai ideologi bangsa berarti Pancasila menjadi pedoman hidup bagi seluruh rakyat Indonesia. Nilai-nilai yang terkandung dalam Pancasila digunakan untuk mengatur kehidupan bermasyarakat, berbangsa, dan bernegara.</p><p data-start=\"1103\" data-end=\"1242\">Pancasila juga menjadi dasar dalam mengambil keputusan, membuat kebijakan, serta menyelesaikan berbagai masalah yang terjadi di masyarakat.</p><h2 data-section-id=\"1durm1r\" data-start=\"1244\" data-end=\"1280\"> </h2><h2 data-section-id=\"1durm1r\" data-start=\"1244\" data-end=\"1280\">Fungsi Pancasila sebagai Ideologi</h2><p data-start=\"1281\" data-end=\"1334\">Fungsi Pancasila sebagai ideologi bangsa antara lain:</p><ol data-start=\"1336\" data-end=\"1576\"><li data-section-id=\"zahtol\" data-start=\"1336\" data-end=\"1382\"><p data-start=\"1338\" data-end=\"1382\">Menjadi pedoman dalam kehidupan sehari-hari.</p></li><li data-section-id=\"t7q78e\" data-start=\"1383\" data-end=\"1420\"><p data-start=\"1385\" data-end=\"1420\">Menjadi pemersatu bangsa Indonesia.</p></li><li data-section-id=\"1njmmme\" data-start=\"1421\" data-end=\"1463\"><p data-start=\"1423\" data-end=\"1463\">Menjadi arah dalam pembangunan nasional.</p></li><li data-section-id=\"1cqkhrj\" data-start=\"1464\" data-end=\"1517\"><p data-start=\"1466\" data-end=\"1517\">Menjadi dasar dalam menjaga persatuan dan kesatuan.</p></li><li data-section-id=\"1l23j2g\" data-start=\"1518\" data-end=\"1576\"><p data-start=\"1520\" data-end=\"1576\">Menjadi pegangan dalam menghadapi pengaruh budaya asing.</p></li></ol><h2 data-section-id=\"1wewag6\" data-start=\"1578\" data-end=\"1626\"> </h2><h2 data-section-id=\"1wewag6\" data-start=\"1578\" data-end=\"1626\">Pancasila dalam Menghadapi Perkembangan Zaman</h2><p data-start=\"1627\" data-end=\"1822\">Di era modern, masyarakat menghadapi berbagai perubahan, seperti perkembangan teknologi, globalisasi, dan masuknya budaya asing. Perubahan tersebut dapat memberikan dampak positif maupun negatif.</p><p data-start=\"1824\" data-end=\"2055\">Dengan berpegang pada Pancasila, masyarakat dapat menyaring pengaruh luar yang tidak sesuai dengan nilai bangsa Indonesia. Pancasila membantu masyarakat tetap menjaga sikap toleransi, persatuan, keadilan, dan tanggung jawab sosial.</p><h2 data-section-id=\"ukmz3h\" data-start=\"2057\" data-end=\"2096\"> </h2><h2 data-section-id=\"ukmz3h\" data-start=\"2057\" data-end=\"2096\">Penerapan Pancasila sebagai Ideologi</h2><p data-start=\"2097\" data-end=\"2154\">Contoh penerapan Pancasila sebagai ideologi bangsa yaitu:</p><ol data-start=\"2156\" data-end=\"2347\"><li data-section-id=\"1xvl7hf\" data-start=\"2156\" data-end=\"2197\"><p data-start=\"2158\" data-end=\"2197\">Menghormati perbedaan agama dan budaya.</p></li><li data-section-id=\"74ika6\" data-start=\"2198\" data-end=\"2225\"><p data-start=\"2200\" data-end=\"2225\">Menjaga persatuan bangsa.</p></li><li data-section-id=\"o5fnmw\" data-start=\"2226\" data-end=\"2278\"><p data-start=\"2228\" data-end=\"2278\">Mengutamakan musyawarah dalam mengambil keputusan.</p></li><li data-section-id=\"1p1gfgh\" data-start=\"2279\" data-end=\"2309\"><p data-start=\"2281\" data-end=\"2309\">Bersikap adil kepada sesama.</p></li><li data-section-id=\"wvj3lw\" data-start=\"2310\" data-end=\"2347\"><p data-start=\"2312\" data-end=\"2347\">Menggunakan teknologi secara bijak.</p></li></ol>','Pancasila sebagai Ideologi Bangsa','','publish','open','closed','','pancasila-sebagai-ideologi-bangsa','','','2026-06-16 11:23:00','2026-06-16 11:23:00','',1198,'http://localhost/wordpress/courses/pancasila/lessons/pancasila-sebagai-ideologi-bangsa/',1,'lesson','',0),(1200,1,'2026-06-16 11:23:15','2026-06-16 11:23:15','<h2 data-section-id=\"16bvovm\" data-start=\"2674\" data-end=\"2684\">Latihan</h2><ol data-start=\"2685\" data-end=\"2929\"><li data-section-id=\"11srx7l\" data-start=\"2685\" data-end=\"2722\"><p data-start=\"2688\" data-end=\"2722\">Apa yang dimaksud dengan ideologi?</p></li><li data-section-id=\"ophljh\" data-start=\"2723\" data-end=\"2776\"><p data-start=\"2726\" data-end=\"2776\">Mengapa Pancasila disebut sebagai ideologi bangsa?</p></li><li data-section-id=\"1is8del\" data-start=\"2777\" data-end=\"2823\"><p data-start=\"2780\" data-end=\"2823\">Sebutkan fungsi Pancasila sebagai ideologi.</p></li><li data-section-id=\"mg553o\" data-start=\"2824\" data-end=\"2877\"><p data-start=\"2827\" data-end=\"2877\">Bagaimana cara menerapkan Pancasila di era modern?</p></li><li data-section-id=\"pitxwc\" data-start=\"2878\" data-end=\"2929\"><p data-start=\"2881\" data-end=\"2929\">Mengapa Pancasila penting bagi bangsa Indonesia?</p></li></ol>','Latihan 7','','publish','open','closed','','latihan-7-2','','','2026-06-16 11:23:15','2026-06-16 11:23:15','',1198,'http://localhost/wordpress/courses/pancasila/lessons/latihan-7-2/',2,'lesson','',0),(1201,1,'2026-06-16 11:23:28','2026-06-16 11:23:28','<h2 data-section-id=\"xl0rbl\" data-start=\"2931\" data-end=\"2939\">Tugas</h2><p data-start=\"2940\" data-end=\"3022\" data-is-last-node=\"\" data-is-only-node=\"\">Jelaskan pentingnya Pancasila sebagai ideologi bangsa dalam kehidupan sehari-hari.</p>','Tugas 7','','publish','open','closed','','tugas-7-2','','','2026-06-16 11:23:28','2026-06-16 11:23:28','',1198,'http://localhost/wordpress/courses/pancasila/lessons/tugas-7-2/',3,'lesson','',0),(1202,1,'2026-06-16 13:13:15','2026-06-16 13:13:15','','Evaluasi','','publish','closed','closed','','pertemuan-8-2','','','2026-06-16 13:13:15','2026-06-16 13:13:15','',1009,'http://localhost/wordpress/topics/pertemuan-8-2/',8,'topics','',0),(1203,1,'2026-06-16 11:24:31','2026-06-16 11:24:31','','Pertemuan 7','','publish','closed','closed','','pertemuan-7-3','','','2026-06-16 11:24:31','2026-06-16 11:24:31','',1016,'http://localhost/wordpress/topics/pertemuan-7-3/',7,'topics','',0),(1204,1,'2026-06-16 11:26:36','2026-06-16 11:26:36','<h2 data-section-id=\"lnz3v4\" data-start=\"48\" data-end=\"70\">Tujuan Pembelajaran</h2><p data-start=\"72\" data-end=\"132\">Setelah mengikuti pertemuan ini, mahasiswa diharapkan mampu:</p><ol data-start=\"134\" data-end=\"499\"><li data-section-id=\"i0dw3e\" data-start=\"134\" data-end=\"177\">Menjelaskan pengertian barisan bilangan.</li><li data-section-id=\"1mk0v54\" data-start=\"178\" data-end=\"223\">Menjelaskan pengertian barisan aritmetika.</li><li data-section-id=\"xfa3l8\" data-start=\"224\" data-end=\"268\">Menentukan beda dalam barisan aritmetika.</li><li data-section-id=\"1udme1z\" data-start=\"269\" data-end=\"317\">Menentukan suku ke-n dari barisan aritmetika.</li><li data-section-id=\"92q2bt\" data-start=\"318\" data-end=\"361\">Menjelaskan pengertian deret aritmetika.</li><li data-section-id=\"1qfdq1j\" data-start=\"362\" data-end=\"415\">Menghitung jumlah n suku pertama deret aritmetika.</li><li data-section-id=\"19gedjc\" data-start=\"416\" data-end=\"499\">Menerapkan konsep barisan dan deret aritmetika dalam soal kehidupan sehari-hari.</li></ol><h1 data-section-id=\"1yqrbt0\" data-start=\"506\" data-end=\"527\"> </h1><h1 data-section-id=\"1yqrbt0\" data-start=\"506\" data-end=\"527\">Materi Pembelajaran</h1><h2 data-section-id=\"1asc287\" data-start=\"529\" data-end=\"562\">1. Pengertian Barisan Bilangan</h2><p data-start=\"564\" data-end=\"681\">Barisan bilangan adalah susunan bilangan yang memiliki pola tertentu. Setiap bilangan dalam barisan disebut <strong data-start=\"672\" data-end=\"680\">suku</strong>.</p><p data-start=\"683\" data-end=\"707\">Contoh barisan bilangan:</p><p data-start=\"709\" data-end=\"728\">2, 4, 6, 8, 10, ...</p><p data-start=\"730\" data-end=\"752\">Pada barisan tersebut:</p><ul data-start=\"754\" data-end=\"845\"><li data-section-id=\"jnlqgx\" data-start=\"754\" data-end=\"772\">Suku pertama = 2</li><li data-section-id=\"117de6f\" data-start=\"773\" data-end=\"789\">Suku kedua = 4</li><li data-section-id=\"1huv8xa\" data-start=\"790\" data-end=\"807\">Suku ketiga = 6</li><li data-section-id=\"b7u56e\" data-start=\"808\" data-end=\"826\">Suku keempat = 8</li><li data-section-id=\"wgh44r\" data-start=\"827\" data-end=\"845\">Suku kelima = 10</li></ul><p data-start=\"847\" data-end=\"991\">Barisan bilangan biasanya memiliki pola. Pola tersebut dapat berupa penambahan, pengurangan, perkalian, pembagian, atau aturan tertentu lainnya.</p><p data-start=\"993\" data-end=\"1005\">Contoh lain:</p><p data-start=\"1007\" data-end=\"1029\">5, 10, 15, 20, 25, ...</p><p data-start=\"1031\" data-end=\"1074\">Barisan tersebut memiliki pola bertambah 5.</p><h2 data-section-id=\"ktll05\" data-start=\"1081\" data-end=\"1116\"> </h2><h2 data-section-id=\"ktll05\" data-start=\"1081\" data-end=\"1116\">2. Pengertian Barisan Aritmetika</h2><p data-start=\"1118\" data-end=\"1230\">Barisan aritmetika adalah barisan bilangan yang memiliki selisih atau beda yang tetap antara dua suku berurutan.</p><p data-start=\"1232\" data-end=\"1317\">Selisih tetap tersebut disebut <strong data-start=\"1263\" data-end=\"1271\">beda</strong> dan biasanya dilambangkan dengan huruf <strong data-start=\"1311\" data-end=\"1316\">b</strong>.</p><p data-start=\"1319\" data-end=\"1326\">Contoh:</p><p data-start=\"1328\" data-end=\"1348\">3, 6, 9, 12, 15, ...</p><p data-start=\"1350\" data-end=\"1427\">Barisan tersebut merupakan barisan aritmetika karena setiap suku bertambah 3.</p><p data-start=\"1429\" data-end=\"1434\">Beda:</p><p data-start=\"1436\" data-end=\"1486\">6 - 3 = 3<br data-start=\"1445\" data-end=\"1448\" />9 - 6 = 3<br data-start=\"1457\" data-end=\"1460\" />12 - 9 = 3<br data-start=\"1470\" data-end=\"1473\" />15 - 12 = 3</p><p data-start=\"1488\" data-end=\"1578\">Karena selisihnya selalu sama, yaitu 3, maka barisan tersebut termasuk barisan aritmetika.</p><p data-start=\"1488\" data-end=\"1578\"> </p><h2 data-section-id=\"fmcpz4\" data-start=\"1585\" data-end=\"1621\">3. Unsur-Unsur Barisan Aritmetika</h2><p data-start=\"1623\" data-end=\"1687\">Dalam barisan aritmetika terdapat beberapa unsur penting, yaitu:</p><h3 data-section-id=\"19ycr73\" data-start=\"1689\" data-end=\"1708\">a. Suku Pertama</h3><p data-start=\"1710\" data-end=\"1822\">Suku pertama adalah bilangan pertama dalam suatu barisan. Suku pertama biasanya dilambangkan dengan huruf <strong data-start=\"1816\" data-end=\"1821\">a</strong>.</p><p data-start=\"1824\" data-end=\"1831\">Contoh:</p><p data-start=\"1833\" data-end=\"1855\">7, 10, 13, 16, 19, ...</p><p data-start=\"1857\" data-end=\"1879\">Suku pertama adalah 7.</p><p data-start=\"1881\" data-end=\"1886\">Maka:</p><p data-start=\"1888\" data-end=\"1893\">a = 7</p><h3 data-section-id=\"1je44so\" data-start=\"1895\" data-end=\"1906\">b. Beda</h3><p data-start=\"1908\" data-end=\"2006\">Beda adalah selisih antara dua suku yang berurutan. Beda biasanya dilambangkan dengan huruf <strong data-start=\"2000\" data-end=\"2005\">b</strong>.</p><p data-start=\"2008\" data-end=\"2019\">Rumus beda:</p><p data-start=\"2021\" data-end=\"2036\"><strong data-start=\"2021\" data-end=\"2036\">b = U₂ - U₁</strong></p><p data-start=\"2038\" data-end=\"2042\">atau</p><p data-start=\"2044\" data-end=\"2059\"><strong data-start=\"2044\" data-end=\"2059\">b = U₃ - U₂</strong></p><p data-start=\"2061\" data-end=\"2068\">Contoh:</p><p data-start=\"2070\" data-end=\"2092\">7, 10, 13, 16, 19, ...</p><p data-start=\"2094\" data-end=\"2099\">Beda:</p><p data-start=\"2101\" data-end=\"2141\">10 - 7 = 3<br data-start=\"2111\" data-end=\"2114\" />13 - 10 = 3<br data-start=\"2125\" data-end=\"2128\" />16 - 13 = 3</p><p data-start=\"2143\" data-end=\"2148\">Maka:</p><p data-start=\"2150\" data-end=\"2155\">b = 3</p><h3 data-section-id=\"5mc7fi\" data-start=\"2157\" data-end=\"2173\">c. Suku ke-n</h3><p data-start=\"2175\" data-end=\"2279\">Suku ke-n adalah suku pada urutan tertentu dalam barisan. Suku ke-n biasanya dilambangkan dengan <strong data-start=\"2272\" data-end=\"2278\">Uₙ</strong>.</p><p data-start=\"2281\" data-end=\"2288\">Contoh:</p><p data-start=\"2290\" data-end=\"2325\">Pada barisan 7, 10, 13, 16, 19, ...</p><ul data-start=\"2327\" data-end=\"2375\"><li data-section-id=\"1m6g0t2\" data-start=\"2327\" data-end=\"2335\">U₁ = 7</li><li data-section-id=\"2rcuo3\" data-start=\"2336\" data-end=\"2345\">U₂ = 10</li><li data-section-id=\"3d8va9\" data-start=\"2346\" data-end=\"2355\">U₃ = 13</li><li data-section-id=\"1xwu83n\" data-start=\"2356\" data-end=\"2365\">U₄ = 16</li><li data-section-id=\"1yiq8q5\" data-start=\"2366\" data-end=\"2375\">U₅ = 19</li></ul><h2 data-section-id=\"o826er\" data-start=\"2382\" data-end=\"2422\"> </h2><h2 data-section-id=\"o826er\" data-start=\"2382\" data-end=\"2422\">4. Rumus Suku ke-n Barisan Aritmetika</h2><p data-start=\"2424\" data-end=\"2466\">Rumus suku ke-n barisan aritmetika adalah:</p><p data-start=\"2468\" data-end=\"2489\"><strong data-start=\"2468\" data-end=\"2489\">Uₙ = a + (n - 1)b</strong></p><p data-start=\"2491\" data-end=\"2502\">Keterangan:</p><ul data-start=\"2504\" data-end=\"2590\"><li data-section-id=\"9aohl8\" data-start=\"2504\" data-end=\"2524\"><strong data-start=\"2506\" data-end=\"2512\">Uₙ</strong> = suku ke-n</li><li data-section-id=\"1swdnea\" data-start=\"2525\" data-end=\"2547\"><strong data-start=\"2527\" data-end=\"2532\">a</strong> = suku pertama</li><li data-section-id=\"1nps2hn\" data-start=\"2548\" data-end=\"2575\"><strong data-start=\"2550\" data-end=\"2555\">n</strong> = nomor urutan suku</li><li data-section-id=\"vzjvf9\" data-start=\"2576\" data-end=\"2590\"><strong data-start=\"2578\" data-end=\"2583\">b</strong> = beda</li></ul><h2 data-section-id=\"12i6wfo\" data-start=\"3533\" data-end=\"3565\"> </h2><h2 data-section-id=\"12i6wfo\" data-start=\"3533\" data-end=\"3565\">5. Pengertian Deret Aritmetika</h2><p data-start=\"3567\" data-end=\"3638\">Deret aritmetika adalah jumlah dari suku-suku dalam barisan aritmetika.</p><p data-start=\"3640\" data-end=\"3666\">Contoh barisan aritmetika:</p><p data-start=\"3668\" data-end=\"3682\">2, 4, 6, 8, 10</p><p data-start=\"3684\" data-end=\"3751\">Jika suku-suku tersebut dijumlahkan, maka menjadi deret aritmetika:</p><p data-start=\"3753\" data-end=\"3771\">2 + 4 + 6 + 8 + 10</p><p data-start=\"3773\" data-end=\"3782\">Hasilnya:</p><p data-start=\"3784\" data-end=\"3807\">2 + 4 + 6 + 8 + 10 = 30</p><p data-start=\"3809\" data-end=\"3847\">Jadi, jumlah 5 suku pertama adalah 30.</p><h2 data-section-id=\"1451mf0\" data-start=\"3854\" data-end=\"3904\"> </h2><h2 data-section-id=\"1451mf0\" data-start=\"3854\" data-end=\"3904\">6. Rumus Jumlah n Suku Pertama Deret Aritmetika</h2><p data-start=\"3906\" data-end=\"3958\">Rumus jumlah n suku pertama deret aritmetika adalah:</p><p data-start=\"3960\" data-end=\"3983\"><strong data-start=\"3960\" data-end=\"3983\">Sₙ = n/2 × (a + Uₙ)</strong></p><p data-start=\"3985\" data-end=\"4009\">atau dapat juga ditulis:</p><p data-start=\"4011\" data-end=\"4041\"><strong data-start=\"4011\" data-end=\"4041\">Sₙ = n/2 × [2a + (n - 1)b]</strong></p><p data-start=\"4043\" data-end=\"4054\">Keterangan:</p><ul data-start=\"4056\" data-end=\"4169\"><li data-section-id=\"3vfhnk\" data-start=\"4056\" data-end=\"4088\"><strong data-start=\"4058\" data-end=\"4064\">Sₙ</strong> = jumlah n suku pertama</li><li data-section-id=\"tew0fx\" data-start=\"4089\" data-end=\"4110\"><strong data-start=\"4091\" data-end=\"4096\">n</strong> = banyak suku</li><li data-section-id=\"1swdnea\" data-start=\"4111\" data-end=\"4133\"><strong data-start=\"4113\" data-end=\"4118\">a</strong> = suku pertama</li><li data-section-id=\"9aohl8\" data-start=\"4134\" data-end=\"4154\"><strong data-start=\"4136\" data-end=\"4142\">Uₙ</strong> = suku ke-n</li><li data-section-id=\"vzjvf9\" data-start=\"4155\" data-end=\"4169\"><strong data-start=\"4157\" data-end=\"4162\">b</strong> = beda</li></ul>','Barisan dan Deret Aritmetika','','publish','open','closed','','barisan-dan-deret-aritmetika','','','2026-06-16 11:26:36','2026-06-16 11:26:36','',1203,'http://localhost/wordpress/courses/matematika-dasar/lessons/barisan-dan-deret-aritmetika/',1,'lesson','',0),(1205,1,'2026-06-16 11:27:15','2026-06-16 11:27:15','<h2 data-section-id=\"nujz7r\" data-start=\"7472\" data-end=\"7493\">Latihan</h2><p data-start=\"7495\" data-end=\"7545\">Kerjakan soal berikut dengan langkah penyelesaian.</p><ol data-start=\"7573\" data-end=\"7872\"><li data-section-id=\"xuv7nk\" data-start=\"7573\" data-end=\"7623\">Tentukan beda dari barisan 2, 5, 8, 11, 14, ...</li><li data-section-id=\"d7o7a2\" data-start=\"7624\" data-end=\"7677\">Tentukan beda dari barisan 10, 15, 20, 25, 30, ...</li><li data-section-id=\"19iclf6\" data-start=\"7678\" data-end=\"7731\">Tentukan beda dari barisan 25, 22, 19, 16, 13, ...</li><li data-section-id=\"s455ft\" data-start=\"7732\" data-end=\"7801\">Tentukan suku pertama dan beda dari barisan 6, 10, 14, 18, 22, ...</li><li data-section-id=\"m2fjmf\" data-start=\"7802\" data-end=\"7872\">Tentukan suku pertama dan beda dari barisan 40, 35, 30, 25, 20, ...</li></ol><h2 data-section-id=\"w8ohmc\" data-start=\"7874\" data-end=\"7900\"> </h2>','Latihan 7','','publish','open','closed','','latihan-7-3','','','2026-06-16 11:27:15','2026-06-16 11:27:15','',1203,'http://localhost/wordpress/courses/matematika-dasar/lessons/latihan-7-3/',2,'lesson','',0),(1206,1,'2026-06-16 11:28:05','2026-06-16 11:28:05','<h2 data-section-id=\"1dwa1k4\" data-start=\"0\" data-end=\"21\">Tugas Pertemuan </h2><p data-start=\"55\" data-end=\"105\">Kerjakan soal berikut dengan langkah penyelesaian:</p><ol data-start=\"107\" data-end=\"334\"><li data-section-id=\"zk1ga8\" data-start=\"107\" data-end=\"175\">Diketahui barisan 4, 8, 12, 16, 20, ...<br data-start=\"149\" data-end=\"152\" />Tentukan suku ke-10.</li><li data-section-id=\"qlya24\" data-start=\"177\" data-end=\"255\">Diketahui barisan 5, 10, 15, 20, 25, ...<br data-start=\"220\" data-end=\"223\" />Hitung jumlah 8 suku pertama.</li><li data-section-id=\"rqalux\" data-start=\"257\" data-end=\"334\">Buatlah 1 contoh penerapan barisan aritmetika dalam kehidupan sehari-hari.</li></ol>','Tugas 7','','publish','open','closed','','tugas-7-3','','','2026-06-16 11:28:05','2026-06-16 11:28:05','',1203,'http://localhost/wordpress/courses/matematika-dasar/lessons/tugas-7-3/',3,'lesson','',0),(1207,1,'2026-06-16 11:28:12','2026-06-16 11:28:12','<table class=\"wp-list-table widefat fixed striped table-view-list forms\"><tbody id=\"the-list\" data-wp-lists=\"list:form\"><tr><td class=\"shortcode column-shortcode\" data-colname=\"Shortcode\">[wpforms id=\"1030\"]</td></tr></tbody></table>','Presentasi','','publish','open','closed','','presentasi','','','2026-06-16 11:42:39','2026-06-16 11:42:39','',1203,'http://localhost/wordpress/courses/matematika-dasar/lessons/presentasi/',4,'lesson','',0),(1208,1,'2026-06-16 13:17:45','2026-06-16 13:17:45','','Evaluasi','','publish','closed','closed','','pertemuan-8-3','','','2026-06-16 13:17:45','2026-06-16 13:17:45','',1016,'http://localhost/wordpress/topics/pertemuan-8-3/',8,'topics','',0),(1209,1,'2026-06-16 11:31:05','2026-06-16 11:31:05','<table class=\"wp-list-table widefat fixed striped table-view-list forms\"><tbody id=\"the-list\" data-wp-lists=\"list:form\"><tr><td class=\"shortcode column-shortcode\" data-colname=\"Shortcode\">[wpforms id=\"1030\"]</td></tr></tbody></table>','Presensi','','publish','open','closed','','presensi-32','','','2026-06-16 11:41:33','2026-06-16 11:41:33','',1198,'http://localhost/wordpress/courses/pancasila/lessons/presensi-32/',4,'lesson','',0),(1210,1,'2026-06-16 11:31:53','2026-06-16 11:31:53','','Pertemuan 7','','publish','closed','closed','','pertemuan-7-4','','','2026-06-16 11:31:53','2026-06-16 11:31:53','',1017,'http://localhost/wordpress/topics/pertemuan-7-4/',7,'topics','',0),(1211,1,'2026-06-16 11:32:48','2026-06-16 11:32:48','<h2 data-section-id=\"lnz3v4\" data-start=\"81\" data-end=\"103\">Tujuan Pembelajaran</h2><p data-start=\"105\" data-end=\"165\">Setelah mengikuti pertemuan ini, mahasiswa diharapkan mampu:</p><ol data-start=\"167\" data-end=\"450\"><li data-section-id=\"cg5smj\" data-start=\"167\" data-end=\"217\">Menjelaskan pengertian organisasi profesi guru.</li><li data-section-id=\"lrsd24\" data-start=\"218\" data-end=\"269\">Menjelaskan fungsi organisasi profesi bagi guru.</li><li data-section-id=\"1716hb2\" data-start=\"270\" data-end=\"329\">Menyebutkan contoh organisasi profesi guru di Indonesia.</li><li data-section-id=\"1un7oc6\" data-start=\"330\" data-end=\"384\">Memahami pentingnya perlindungan profesi bagi guru.</li><li data-section-id=\"5y79oz\" data-start=\"385\" data-end=\"450\">Menjelaskan hak dan kewajiban guru sebagai tenaga profesional.</li></ol><h2 data-section-id=\"8vba7q\" data-start=\"480\" data-end=\"520\"> </h2><h2 data-section-id=\"8vba7q\" data-start=\"480\" data-end=\"520\">1. Pengertian Organisasi Profesi Guru</h2><p data-start=\"522\" data-end=\"726\">Organisasi profesi guru adalah wadah atau perkumpulan yang dibentuk oleh para guru untuk mengembangkan kemampuan, menjaga martabat profesi, memperjuangkan hak guru, serta meningkatkan kualitas pendidikan.</p><p data-start=\"728\" data-end=\"946\">Organisasi profesi sangat penting karena guru tidak bekerja sendiri. Guru membutuhkan tempat untuk berbagi pengalaman, mengikuti pelatihan, menyampaikan aspirasi, dan memperoleh perlindungan dalam menjalankan tugasnya.</p><p data-start=\"948\" data-end=\"1004\">Contoh organisasi profesi guru di Indonesia antara lain:</p><ol data-start=\"1006\" data-end=\"1182\"><li data-section-id=\"6eotsl\" data-start=\"1006\" data-end=\"1057\"><strong data-start=\"1009\" data-end=\"1017\">PGRI</strong> atau Persatuan Guru Republik Indonesia.</li><li data-section-id=\"cipy4g\" data-start=\"1058\" data-end=\"1096\"><strong data-start=\"1061\" data-end=\"1068\">IGI</strong> atau Ikatan Guru Indonesia.</li><li data-section-id=\"28nv18\" data-start=\"1097\" data-end=\"1145\"><strong data-start=\"1100\" data-end=\"1108\">MGMP</strong> atau Musyawarah Guru Mata Pelajaran.</li><li data-section-id=\"otq96p\" data-start=\"1146\" data-end=\"1182\"><strong data-start=\"1149\" data-end=\"1156\">KKG</strong> atau Kelompok Kerja Guru.</li></ol><h2 data-section-id=\"cg824s\" data-start=\"1189\" data-end=\"1225\"> </h2><h2 data-section-id=\"cg824s\" data-start=\"1189\" data-end=\"1225\">2. Fungsi Organisasi Profesi Guru</h2><p data-start=\"1227\" data-end=\"1291\">Organisasi profesi guru memiliki beberapa fungsi penting, yaitu:</p><h3 data-section-id=\"lokwve\" data-start=\"1293\" data-end=\"1333\">a. Meningkatkan Profesionalisme Guru</h3><p data-start=\"1335\" data-end=\"1477\">Organisasi profesi membantu guru meningkatkan kemampuan melalui pelatihan, seminar, workshop, diskusi, dan kegiatan pengembangan diri lainnya.</p><p data-start=\"1479\" data-end=\"1486\">Contoh:</p><p data-start=\"1488\" data-end=\"1582\">Guru mengikuti pelatihan pembuatan media pembelajaran digital agar pembelajaran lebih menarik.</p><h3 data-section-id=\"1alqr5b\" data-start=\"1584\" data-end=\"1620\">b. Menjadi Wadah Komunikasi Guru</h3><p data-start=\"1622\" data-end=\"1774\">Organisasi profesi menjadi tempat guru bertukar informasi dan pengalaman mengenai pembelajaran, kurikulum, metode mengajar, dan permasalahan di sekolah.</p><h3 data-section-id=\"1kfgzxq\" data-start=\"1776\" data-end=\"1802\">c. Melindungi Hak Guru</h3><p data-start=\"1804\" data-end=\"1972\">Guru memiliki hak yang perlu dilindungi, seperti hak memperoleh penghasilan yang layak, rasa aman dalam bekerja, kesempatan mengembangkan diri, dan perlakuan yang adil.</p><h3 data-section-id=\"xtwhk5\" data-start=\"1974\" data-end=\"2006\">d. Menjaga Kode Etik Profesi</h3><p data-start=\"2008\" data-end=\"2171\">Organisasi profesi membantu menjaga agar guru bekerja sesuai kode etik. Guru harus bersikap jujur, adil, bertanggung jawab, dan menjadi teladan bagi peserta didik.</p><h3 data-section-id=\"cordqv\" data-start=\"2173\" data-end=\"2208\">e. Meningkatkan Mutu Pendidikan</h3><p data-start=\"2210\" data-end=\"2358\">Jika guru semakin profesional, maka proses pembelajaran juga akan semakin baik. Hal ini dapat berdampak pada peningkatan mutu pendidikan di sekolah.</p><h2 data-section-id=\"2cyebg\" data-start=\"2365\" data-end=\"2401\"> </h2><h2 data-section-id=\"2cyebg\" data-start=\"2365\" data-end=\"2401\">3. Contoh Organisasi Profesi Guru</h2><h3 data-section-id=\"g913fp\" data-start=\"2403\" data-end=\"2414\">a. PGRI</h3><p data-start=\"2416\" data-end=\"2572\">PGRI adalah organisasi profesi guru yang berperan dalam memperjuangkan hak, meningkatkan kesejahteraan, dan mengembangkan profesionalisme guru di Indonesia.</p><h3 data-section-id=\"1048jgt\" data-start=\"2574\" data-end=\"2584\">b. IGI</h3><p data-start=\"2586\" data-end=\"2734\">IGI adalah organisasi guru yang berfokus pada peningkatan kompetensi guru, terutama dalam inovasi pembelajaran dan pemanfaatan teknologi pendidikan.</p><h3 data-section-id=\"1b7t7r0\" data-start=\"2736\" data-end=\"2747\">c. MGMP</h3><p data-start=\"2749\" data-end=\"2954\">MGMP adalah forum guru mata pelajaran yang biasanya berada di tingkat SMP, SMA, atau SMK. Melalui MGMP, guru dapat berdiskusi tentang materi, perangkat pembelajaran, soal, penilaian, dan strategi mengajar.</p><h3 data-section-id=\"ywjjrf\" data-start=\"2956\" data-end=\"2966\">d. KKG</h3><p data-start=\"2968\" data-end=\"3168\">KKG adalah forum kerja guru, terutama untuk guru sekolah dasar. KKG digunakan untuk meningkatkan kemampuan guru dalam mengajar, menyusun perangkat pembelajaran, dan menyelesaikan masalah pembelajaran.</p><h2 data-section-id=\"1aumtyd\" data-start=\"3175\" data-end=\"3206\"> </h2><h2 data-section-id=\"1aumtyd\" data-start=\"3175\" data-end=\"3206\">4. Perlindungan Profesi Guru</h2><p data-start=\"3208\" data-end=\"3466\">Perlindungan profesi guru adalah upaya untuk memberikan rasa aman kepada guru dalam menjalankan tugasnya. Guru perlu mendapat perlindungan karena dalam pekerjaannya, guru berhadapan langsung dengan peserta didik, orang tua, masyarakat, dan aturan pendidikan.</p><p data-start=\"3468\" data-end=\"3571\">Perlindungan profesi penting agar guru dapat bekerja secara tenang, profesional, dan bertanggung jawab.</p><h2 data-section-id=\"1tz8ph8\" data-start=\"3573\" data-end=\"3608\">Bentuk Perlindungan Profesi Guru</h2><p data-start=\"3610\" data-end=\"3643\">Perlindungan guru dapat meliputi:</p><ol data-start=\"3645\" data-end=\"4143\"><li data-section-id=\"1l2k1pv\" data-start=\"3645\" data-end=\"3773\"><strong data-start=\"3648\" data-end=\"3670\">Perlindungan hukum</strong><br data-start=\"3670\" data-end=\"3673\" />Guru mendapatkan perlindungan jika menghadapi masalah hukum saat menjalankan tugas sesuai aturan.</li><li data-section-id=\"1moz7bz\" data-start=\"3775\" data-end=\"3900\"><strong data-start=\"3778\" data-end=\"3802\">Perlindungan profesi</strong><br data-start=\"3802\" data-end=\"3805\" />Guru dilindungi agar dapat menjalankan tugas profesionalnya tanpa tekanan yang tidak sesuai.</li><li data-section-id=\"mdd9hs\" data-start=\"3902\" data-end=\"4000\"><strong data-start=\"3905\" data-end=\"3939\">Perlindungan keselamatan kerja</strong><br data-start=\"3939\" data-end=\"3942\" />Guru berhak memperoleh rasa aman di lingkungan sekolah.</li><li data-section-id=\"602ejn\" data-start=\"4002\" data-end=\"4143\"><strong data-start=\"4005\" data-end=\"4047\">Perlindungan dari perlakuan tidak adil</strong><br data-start=\"4047\" data-end=\"4050\" />Guru tidak boleh diperlakukan secara diskriminatif atau dirugikan tanpa alasan yang jelas.</li></ol><h2 data-section-id=\"vtibxl\" data-start=\"4150\" data-end=\"4164\"> </h2><h2 data-section-id=\"vtibxl\" data-start=\"4150\" data-end=\"4164\">5. Hak Guru</h2><p data-start=\"4166\" data-end=\"4233\">Guru sebagai tenaga profesional memiliki beberapa hak, antara lain:</p><ol data-start=\"4235\" data-end=\"4585\"><li data-section-id=\"r40n05\" data-start=\"4235\" data-end=\"4273\">Mendapatkan penghasilan yang layak.</li><li data-section-id=\"1xlc985\" data-start=\"4274\" data-end=\"4326\">Mendapatkan perlindungan dalam menjalankan tugas.</li><li data-section-id=\"1pb5fl0\" data-start=\"4327\" data-end=\"4384\">Mendapatkan kesempatan untuk mengembangkan kompetensi.</li><li data-section-id=\"1u6qkph\" data-start=\"4385\" data-end=\"4434\">Memperoleh rasa aman dan nyaman dalam bekerja.</li><li data-section-id=\"b9i2dg\" data-start=\"4435\" data-end=\"4484\">Menggunakan sarana dan prasarana pembelajaran.</li><li data-section-id=\"1osmqnr\" data-start=\"4485\" data-end=\"4546\">Memberikan penilaian kepada peserta didik secara objektif.</li><li data-section-id=\"1x4cj7e\" data-start=\"4547\" data-end=\"4585\">Bergabung dalam organisasi profesi.</li></ol><h2 data-section-id=\"iyku5a\" data-start=\"4592\" data-end=\"4612\"> </h2><h2 data-section-id=\"iyku5a\" data-start=\"4592\" data-end=\"4612\">6. Kewajiban Guru</h2><p data-start=\"4614\" data-end=\"4671\">Selain memiliki hak, guru juga memiliki kewajiban, yaitu:</p><ol data-start=\"4673\" data-end=\"5016\"><li data-section-id=\"m6x5vl\" data-start=\"4673\" data-end=\"4714\">Melaksanakan pembelajaran dengan baik.</li><li data-section-id=\"1w1vonz\" data-start=\"4715\" data-end=\"4756\">Mendidik dan membimbing peserta didik.</li><li data-section-id=\"w495qc\" data-start=\"4757\" data-end=\"4813\">Menilai dan mengevaluasi hasil belajar peserta didik.</li><li data-section-id=\"1p2vg7h\" data-start=\"4814\" data-end=\"4848\">Menjaga kode etik profesi guru.</li><li data-section-id=\"u6uaxx\" data-start=\"4849\" data-end=\"4887\">Menjadi teladan bagi peserta didik.</li><li data-section-id=\"oszhey\" data-start=\"4888\" data-end=\"4936\">Mengembangkan kemampuan secara berkelanjutan.</li><li data-section-id=\"u4qdul\" data-start=\"4937\" data-end=\"4981\">Bersikap adil kepada semua peserta didik.</li><li data-section-id=\"1vzgpo5\" data-start=\"4982\" data-end=\"5016\">Menjaga nama baik profesi guru.</li></ol><h2 data-section-id=\"1m20zs0\" data-start=\"5023\" data-end=\"5080\"> </h2><h2 data-section-id=\"1m20zs0\" data-start=\"5023\" data-end=\"5080\">7. Pentingnya Organisasi dan Perlindungan Profesi Guru</h2><p data-start=\"5082\" data-end=\"5312\">Organisasi dan perlindungan profesi guru sangat penting karena guru memiliki tanggung jawab besar dalam dunia pendidikan. Guru tidak hanya menyampaikan materi, tetapi juga membentuk karakter, sikap, dan keterampilan peserta didik.</p><p data-start=\"5314\" data-end=\"5528\">Dengan adanya organisasi profesi, guru dapat meningkatkan kualitas diri dan memiliki wadah untuk berkomunikasi. Dengan adanya perlindungan profesi, guru dapat menjalankan tugasnya dengan rasa aman dan percaya diri.</p>','Organisasi Profesi Guru dan Perlindungan Profesi Kependidikan','','publish','open','closed','','organisasi-profesi-guru-dan-perlindungan-profesi-kependidikan','','','2026-06-16 11:32:48','2026-06-16 11:32:48','',1210,'http://localhost/wordpress/courses/profesi-kependidikan/lessons/organisasi-profesi-guru-dan-perlindungan-profesi-kependidikan/',1,'lesson','',0),(1212,1,'2026-06-16 11:33:05','2026-06-16 11:33:05','<h2 data-section-id=\"nujz7r\" data-start=\"6681\" data-end=\"6702\">Latihan </h2><p data-start=\"6704\" data-end=\"6726\">Kerjakan soal berikut.</p><ol data-start=\"6728\" data-end=\"7245\"><li data-section-id=\"stgs0u\" data-start=\"6728\" data-end=\"6780\">Apa yang dimaksud dengan organisasi profesi guru?</li><li data-section-id=\"1nyi5ev\" data-start=\"6781\" data-end=\"6839\">Sebutkan 4 contoh organisasi profesi guru di Indonesia.</li><li data-section-id=\"1mt1qn\" data-start=\"6840\" data-end=\"6883\">Apa fungsi organisasi profesi bagi guru?</li><li data-section-id=\"1z07cqa\" data-start=\"6884\" data-end=\"6941\">Mengapa guru perlu bergabung dalam organisasi profesi?</li><li data-section-id=\"pk9el1\" data-start=\"6942\" data-end=\"6996\">Apa yang dimaksud dengan perlindungan profesi guru?</li><li data-section-id=\"oyycy0\" data-start=\"6997\" data-end=\"7044\">Sebutkan 3 bentuk perlindungan profesi guru.</li></ol>','Latihan 7','','publish','open','closed','','latihan-7-4','','','2026-06-16 11:34:18','2026-06-16 11:34:18','',1210,'http://localhost/wordpress/courses/profesi-kependidikan/lessons/latihan-7-4/',2,'lesson','',0),(1213,1,'2026-06-16 11:33:51','2026-06-16 11:33:51','<h2 data-section-id=\"1rrbd2f\" data-start=\"7359\" data-end=\"7377\">Tugas</h2><p data-start=\"7379\" data-end=\"7428\">Buatlah jawaban singkat dengan ketentuan berikut:</p><ol data-start=\"7430\" data-end=\"7646\"><li data-section-id=\"1d90r3h\" data-start=\"7430\" data-end=\"7477\">Jelaskan pengertian organisasi profesi guru.</li><li data-section-id=\"1lztkds\" data-start=\"7478\" data-end=\"7523\">Sebutkan 2 contoh organisasi profesi guru.</li><li data-section-id=\"suqm20\" data-start=\"7524\" data-end=\"7574\">Jelaskan 3 fungsi organisasi profesi bagi guru.</li><li data-section-id=\"1r7xdn7\" data-start=\"7575\" data-end=\"7646\">Tuliskan pendapat Anda tentang pentingnya perlindungan profesi guru.</li></ol>','Tugas','','publish','open','closed','','tugas','','','2026-06-16 11:33:51','2026-06-16 11:33:51','',1210,'http://localhost/wordpress/courses/profesi-kependidikan/lessons/tugas/',3,'lesson','',0),(1214,1,'2026-06-16 11:34:23','2026-06-16 11:34:23','<table class=\"wp-list-table widefat fixed striped table-view-list forms\"><tbody id=\"the-list\" data-wp-lists=\"list:form\"><tr><td class=\"shortcode column-shortcode\" data-colname=\"Shortcode\">[wpforms id=\"1030\"]</td></tr></tbody></table>','Presensi','','publish','open','closed','','presensi-33','','','2026-06-16 11:34:34','2026-06-16 11:34:34','',1210,'http://localhost/wordpress/courses/profesi-kependidikan/lessons/presensi-33/',4,'lesson','',0),(1215,1,'2026-06-16 13:26:57','2026-06-16 13:26:57','','Evaluasi','','publish','closed','closed','','pertemuan-8-4','','','2026-06-16 13:26:57','2026-06-16 13:26:57','',1017,'http://localhost/wordpress/topics/pertemuan-8-4/',8,'topics','',0),(1216,1,'2026-06-16 11:39:14','2026-06-16 11:39:14','','Pertemuan 7','','publish','closed','closed','','pertemuan-7-5','','','2026-06-16 11:39:14','2026-06-16 11:39:14','',1018,'http://localhost/wordpress/topics/pertemuan-7-5/',7,'topics','',0),(1217,1,'2026-06-16 11:40:32','2026-06-16 11:40:32','<h2 data-section-id=\"lnz3v4\" data-start=\"58\" data-end=\"80\">Tujuan Pembelajaran</h2><p data-start=\"82\" data-end=\"142\">Setelah mengikuti pertemuan ini, mahasiswa diharapkan mampu:</p><ol data-start=\"144\" data-end=\"457\"><li data-section-id=\"3xvs4t\" data-start=\"144\" data-end=\"188\">Menjelaskan pengertian supervisi sekolah.</li><li data-section-id=\"g97duz\" data-start=\"189\" data-end=\"238\">Menjelaskan tujuan supervisi dalam pendidikan.</li><li data-section-id=\"vn6i4p\" data-start=\"239\" data-end=\"291\">Menjelaskan peran kepala sekolah dalam supervisi.</li><li data-section-id=\"o670mg\" data-start=\"292\" data-end=\"343\">Menjelaskan pengertian evaluasi program sekolah.</li><li data-section-id=\"18vcdaz\" data-start=\"344\" data-end=\"389\">Membedakan supervisi dan evaluasi sekolah.</li><li data-section-id=\"iof7iz\" data-start=\"390\" data-end=\"457\">Memberikan contoh pelaksanaan supervisi dan evaluasi di sekolah.</li></ol><h2 data-section-id=\"1cxuro0\" data-start=\"487\" data-end=\"521\"> </h2><h2 data-section-id=\"1cxuro0\" data-start=\"487\" data-end=\"521\">1. Pengertian Supervisi Sekolah</h2><p data-start=\"523\" data-end=\"707\">Supervisi sekolah adalah kegiatan pembinaan, pengawasan, dan pendampingan yang dilakukan untuk membantu guru dan tenaga kependidikan agar dapat melaksanakan tugasnya dengan lebih baik.</p><p data-start=\"709\" data-end=\"855\">Supervisi bukan hanya mencari kesalahan guru, tetapi bertujuan untuk memperbaiki dan meningkatkan kualitas pembelajaran serta pengelolaan sekolah.</p><p data-start=\"857\" data-end=\"1008\">Dalam sekolah, supervisi biasanya dilakukan oleh kepala sekolah, pengawas sekolah, atau pihak yang memiliki wewenang untuk membina kegiatan pendidikan.</p><p data-start=\"1010\" data-end=\"1035\">Contoh supervisi sekolah:</p><ol data-start=\"1037\" data-end=\"1357\"><li data-section-id=\"sik0c9\" data-start=\"1037\" data-end=\"1083\">Kepala sekolah mengamati guru saat mengajar.</li><li data-section-id=\"14k460x\" data-start=\"1084\" data-end=\"1139\">Kepala sekolah memeriksa perangkat pembelajaran guru.</li><li data-section-id=\"decaoq\" data-start=\"1140\" data-end=\"1208\">Pengawas sekolah memberikan masukan terhadap administrasi sekolah.</li><li data-section-id=\"1m2i7jl\" data-start=\"1209\" data-end=\"1278\">Kepala sekolah berdiskusi dengan guru tentang kendala pembelajaran.</li><li data-section-id=\"dw51q8\" data-start=\"1279\" data-end=\"1357\">Sekolah melakukan pembinaan terhadap guru yang mengalami kesulitan mengajar.</li></ol><h2 data-section-id=\"12amdrv\" data-start=\"1364\" data-end=\"1394\"> </h2><h2 data-section-id=\"12amdrv\" data-start=\"1364\" data-end=\"1394\">2. Tujuan Supervisi Sekolah</h2><p data-start=\"1396\" data-end=\"1446\">Supervisi sekolah memiliki beberapa tujuan, yaitu:</p><ol data-start=\"1448\" data-end=\"1882\"><li data-section-id=\"hk2i1c\" data-start=\"1448\" data-end=\"1486\">Meningkatkan kualitas pembelajaran.</li><li data-section-id=\"16nqtu2\" data-start=\"1487\" data-end=\"1532\">Membantu guru memperbaiki metode mengajar.</li><li data-section-id=\"1fl1yrp\" data-start=\"1533\" data-end=\"1572\">Membina guru agar lebih profesional.</li><li data-section-id=\"6lubn9\" data-start=\"1573\" data-end=\"1621\">Mengetahui kendala dalam proses pembelajaran.</li><li data-section-id=\"1docjbi\" data-start=\"1622\" data-end=\"1691\">Meningkatkan kemampuan guru dalam menyusun perangkat pembelajaran.</li><li data-section-id=\"1kkfbsv\" data-start=\"1692\" data-end=\"1739\">Membantu sekolah mencapai tujuan pendidikan.</li><li data-section-id=\"1d9fye4\" data-start=\"1740\" data-end=\"1820\">Meningkatkan kerja sama antara kepala sekolah, guru, dan tenaga kependidikan.</li><li data-section-id=\"1abl2iv\" data-start=\"1821\" data-end=\"1882\">Menciptakan suasana sekolah yang lebih tertib dan efektif.</li></ol><p data-start=\"1884\" data-end=\"2020\">Supervisi yang baik dilakukan dengan cara membimbing, memberi masukan, dan membantu guru mencari solusi, bukan hanya menilai kekurangan.</p><h2 data-section-id=\"oxusti\" data-start=\"2027\" data-end=\"2062\"> </h2><h2 data-section-id=\"oxusti\" data-start=\"2027\" data-end=\"2062\">3. Jenis-Jenis Supervisi Sekolah</h2><h2 data-section-id=\"1m9spzf\" data-start=\"2064\" data-end=\"2088\">a. Supervisi Akademik</h2><p data-start=\"2090\" data-end=\"2181\">Supervisi akademik adalah supervisi yang berhubungan langsung dengan kegiatan pembelajaran.</p><p data-start=\"2183\" data-end=\"2190\">Contoh:</p><ul data-start=\"2192\" data-end=\"2412\"><li data-section-id=\"y1ersg\" data-start=\"2192\" data-end=\"2224\">Memeriksa modul ajar atau RPP.</li><li data-section-id=\"dktdou\" data-start=\"2225\" data-end=\"2267\">Mengamati proses guru mengajar di kelas.</li><li data-section-id=\"he4qf4\" data-start=\"2268\" data-end=\"2317\">Memberikan masukan tentang metode pembelajaran.</li><li data-section-id=\"12ma42h\" data-start=\"2318\" data-end=\"2363\">Mengevaluasi penggunaan media pembelajaran.</li><li data-section-id=\"1cl04fq\" data-start=\"2364\" data-end=\"2412\">Membimbing guru dalam membuat penilaian siswa.</li></ul><p data-start=\"2414\" data-end=\"2487\">Supervisi akademik bertujuan meningkatkan kualitas pembelajaran di kelas.</p><h2 data-section-id=\"51pvr8\" data-start=\"2489\" data-end=\"2518\">b. Supervisi Administratif</h2><p data-start=\"2520\" data-end=\"2616\">Supervisi administratif adalah supervisi yang berkaitan dengan kelengkapan administrasi sekolah.</p><p data-start=\"2618\" data-end=\"2625\">Contoh:</p><ol data-start=\"2627\" data-end=\"2817\"><li data-section-id=\"a4yspx\" data-start=\"2627\" data-end=\"2669\">Pemeriksaan daftar hadir guru dan siswa.</li><li data-section-id=\"2s8khp\" data-start=\"2670\" data-end=\"2701\">Pemeriksaan buku induk siswa.</li><li data-section-id=\"1tr17im\" data-start=\"2702\" data-end=\"2728\">Pemeriksaan arsip surat.</li><li data-section-id=\"s1qcac\" data-start=\"2729\" data-end=\"2768\">Pemeriksaan laporan kegiatan sekolah.</li><li data-section-id=\"x5fpr1\" data-start=\"2769\" data-end=\"2817\">Pemeriksaan dokumen kurikulum dan nilai siswa.</li></ol><p data-start=\"2819\" data-end=\"2925\">Supervisi administratif bertujuan agar pengelolaan sekolah berjalan tertib dan terdokumentasi dengan baik.</p><h2 data-section-id=\"1he0lw6\" data-start=\"2927\" data-end=\"2953\">c. Supervisi Manajerial</h2><p data-start=\"2955\" data-end=\"3025\">Supervisi manajerial berkaitan dengan pengelolaan sekolah secara umum.</p><p data-start=\"3027\" data-end=\"3034\">Contoh:</p><ol data-start=\"3036\" data-end=\"3230\"><li data-section-id=\"17tl9ub\" data-start=\"3036\" data-end=\"3077\">Pengawasan pelaksanaan program sekolah.</li><li data-section-id=\"1heq9h2\" data-start=\"3078\" data-end=\"3113\">Pengelolaan sarana dan prasarana.</li><li data-section-id=\"725d9x\" data-start=\"3114\" data-end=\"3145\">Pengelolaan keuangan sekolah.</li><li data-section-id=\"gq33fj\" data-start=\"3146\" data-end=\"3193\">Pembagian tugas guru dan tenaga kependidikan.</li><li data-section-id=\"kv1n8z\" data-start=\"3194\" data-end=\"3230\">Pelaksanaan program kerja sekolah.</li></ol><p data-start=\"3232\" data-end=\"3323\">Supervisi manajerial bertujuan memastikan seluruh kegiatan sekolah berjalan sesuai rencana.</p><h2 data-section-id=\"1nag58z\" data-start=\"3330\" data-end=\"3372\"> </h2><h2 data-section-id=\"1nag58z\" data-start=\"3330\" data-end=\"3372\">4. Peran Kepala Sekolah dalam Supervisi</h2><p data-start=\"3374\" data-end=\"3570\">Kepala sekolah memiliki peran penting dalam kegiatan supervisi. Kepala sekolah tidak hanya memimpin sekolah, tetapi juga membina guru dan tenaga kependidikan agar mampu bekerja secara profesional.</p><p data-start=\"3572\" data-end=\"3621\">Peran kepala sekolah dalam supervisi antara lain:</p><ol data-start=\"3623\" data-end=\"4158\"><li data-section-id=\"4fnqrp\" data-start=\"3623\" data-end=\"3724\"><strong data-start=\"3626\" data-end=\"3645\">Sebagai pembina</strong><br data-start=\"3645\" data-end=\"3648\" />Kepala sekolah membimbing guru agar dapat meningkatkan kualitas mengajar.</li><li data-section-id=\"qcy29t\" data-start=\"3726\" data-end=\"3829\"><strong data-start=\"3729\" data-end=\"3749\">Sebagai pengawas</strong><br data-start=\"3749\" data-end=\"3752\" />Kepala sekolah memantau pelaksanaan pembelajaran dan administrasi sekolah.</li><li data-section-id=\"fxuooe\" data-start=\"3831\" data-end=\"3938\"><strong data-start=\"3834\" data-end=\"3855\">Sebagai evaluator</strong><br data-start=\"3855\" data-end=\"3858\" />Kepala sekolah menilai apakah kegiatan sekolah sudah berjalan sesuai rencana.</li><li data-section-id=\"118wzq5\" data-start=\"3940\" data-end=\"4045\"><strong data-start=\"3943\" data-end=\"3964\">Sebagai motivator</strong><br data-start=\"3964\" data-end=\"3967\" />Kepala sekolah memberikan semangat kepada guru agar terus memperbaiki diri.</li><li data-section-id=\"a15jtc\" data-start=\"4047\" data-end=\"4158\"><strong data-start=\"4050\" data-end=\"4076\">Sebagai pemberi solusi</strong><br data-start=\"4076\" data-end=\"4079\" />Kepala sekolah membantu guru mencari jalan keluar dari masalah pembelajaran.</li></ol><p data-start=\"4160\" data-end=\"4167\">Contoh:</p><p data-start=\"4169\" data-end=\"4372\">Seorang guru mengalami kesulitan mengelola kelas. Kepala sekolah melakukan observasi, berdiskusi dengan guru, lalu memberikan saran agar guru menggunakan metode pembelajaran yang lebih aktif dan menarik.</p><h2 data-section-id=\"1wxohp2\" data-start=\"4379\" data-end=\"4422\"> </h2><h2 data-section-id=\"1wxohp2\" data-start=\"4379\" data-end=\"4422\">5. Langkah-Langkah Pelaksanaan Supervisi</h2><p data-start=\"4424\" data-end=\"4491\">Supervisi sekolah dapat dilakukan melalui beberapa langkah berikut:</p><h2 data-section-id=\"1bccx9c\" data-start=\"4493\" data-end=\"4520\">a. Perencanaan Supervisi</h2><p data-start=\"4522\" data-end=\"4631\">Pada tahap ini, kepala sekolah menentukan tujuan, jadwal, aspek yang diamati, dan guru yang akan disupervisi.</p><p data-start=\"4633\" data-end=\"4640\">Contoh:</p><p data-start=\"4642\" data-end=\"4726\">Kepala sekolah membuat jadwal supervisi kelas untuk semua guru selama satu semester.</p><h2 data-section-id=\"5zhm6k\" data-start=\"4728\" data-end=\"4755\">b. Pelaksanaan Supervisi</h2><p data-start=\"4757\" data-end=\"4841\">Pada tahap ini, kepala sekolah melakukan pengamatan atau pemeriksaan sesuai rencana.</p><p data-start=\"4843\" data-end=\"4850\">Contoh:</p><p data-start=\"4852\" data-end=\"4923\">Kepala sekolah masuk ke kelas untuk mengamati proses pembelajaran guru.</p><h2 data-section-id=\"1g4dpf5\" data-start=\"4925\" data-end=\"4955\">c. Analisis Hasil Supervisi</h2><p data-start=\"4957\" data-end=\"5031\">Setelah supervisi dilakukan, kepala sekolah menganalisis hasil pengamatan.</p><p data-start=\"5033\" data-end=\"5040\">Contoh:</p><p data-start=\"5042\" data-end=\"5110\">Kepala sekolah mencatat kelebihan dan kekurangan guru saat mengajar.</p><h2 data-section-id=\"1mpyvny\" data-start=\"5112\" data-end=\"5139\">d. Pemberian Umpan Balik</h2><p data-start=\"5141\" data-end=\"5223\">Kepala sekolah menyampaikan hasil supervisi kepada guru secara baik dan membangun.</p><p data-start=\"5225\" data-end=\"5232\">Contoh:</p><p data-start=\"5234\" data-end=\"5320\">Kepala sekolah memberikan saran agar guru lebih banyak menggunakan media pembelajaran.</p><h2 data-section-id=\"4eu9rv\" data-start=\"5322\" data-end=\"5341\">e. Tindak Lanjut</h2><p data-start=\"5343\" data-end=\"5418\">Tindak lanjut dilakukan agar hasil supervisi benar-benar membawa perubahan.</p><p data-start=\"5420\" data-end=\"5427\">Contoh:</p><p data-start=\"5429\" data-end=\"5525\">Guru mengikuti pelatihan, memperbaiki perangkat pembelajaran, atau mencoba metode mengajar baru.</p><h2 data-section-id=\"1kpwe9g\" data-start=\"5532\" data-end=\"5572\"> </h2><h2 data-section-id=\"1kpwe9g\" data-start=\"5532\" data-end=\"5572\">6. Pengertian Evaluasi Program Sekolah</h2><p data-start=\"5574\" data-end=\"5712\">Evaluasi program sekolah adalah kegiatan menilai keberhasilan suatu program sekolah berdasarkan tujuan, pelaksanaan, hasil, dan dampaknya.</p><p data-start=\"5714\" data-end=\"5828\">Evaluasi dilakukan untuk mengetahui apakah program sekolah sudah berjalan dengan baik atau masih perlu diperbaiki.</p><p data-start=\"5830\" data-end=\"5875\">Contoh program sekolah yang perlu dievaluasi:</p><ol data-start=\"5877\" data-end=\"6137\"><li data-section-id=\"dv3sei\" data-start=\"5877\" data-end=\"5905\">Program literasi sekolah.</li><li data-section-id=\"1i1z8a9\" data-start=\"5906\" data-end=\"5936\">Program kedisiplinan siswa.</li><li data-section-id=\"xo4vxv\" data-start=\"5937\" data-end=\"5967\">Program kebersihan sekolah.</li><li data-section-id=\"kjzr7j\" data-start=\"5968\" data-end=\"5995\">Program ekstrakurikuler.</li><li data-section-id=\"yy45ya\" data-start=\"5996\" data-end=\"6033\">Program peningkatan hasil belajar.</li><li data-section-id=\"117k2ij\" data-start=\"6034\" data-end=\"6060\">Program penggunaan LMS.</li><li data-section-id=\"1kpjqzi\" data-start=\"6061\" data-end=\"6090\">Program bimbingan belajar.</li><li data-section-id=\"1umugbj\" data-start=\"6091\" data-end=\"6137\">Program hubungan sekolah dengan masyarakat.</li></ol><h2 data-section-id=\"1qdwtha\" data-start=\"6144\" data-end=\"6181\"> </h2><h2 data-section-id=\"1qdwtha\" data-start=\"6144\" data-end=\"6181\">7. Tujuan Evaluasi Program Sekolah</h2><p data-start=\"6183\" data-end=\"6224\">Evaluasi program sekolah bertujuan untuk:</p><ol data-start=\"6226\" data-end=\"6551\"><li data-section-id=\"jq3dla\" data-start=\"6226\" data-end=\"6261\">Mengetahui keberhasilan program.</li><li data-section-id=\"puj0gu\" data-start=\"6262\" data-end=\"6311\">Mengetahui hambatan dalam pelaksanaan program.</li><li data-section-id=\"16r4ksz\" data-start=\"6312\" data-end=\"6354\">Menilai apakah tujuan program tercapai.</li><li data-section-id=\"i01ze9\" data-start=\"6355\" data-end=\"6411\">Menentukan program perlu dilanjutkan atau diperbaiki.</li><li data-section-id=\"1hgy4f7\" data-start=\"6412\" data-end=\"6460\">Memberikan dasar dalam pengambilan keputusan.</li><li data-section-id=\"zat249\" data-start=\"6461\" data-end=\"6502\">Meningkatkan mutu pengelolaan sekolah.</li><li data-section-id=\"4nmk8q\" data-start=\"6503\" data-end=\"6551\">Membantu sekolah menyusun program berikutnya.</li></ol><p data-start=\"6553\" data-end=\"6560\">Contoh:</p><p data-start=\"6562\" data-end=\"6714\">Sekolah melaksanakan program literasi selama satu semester. Setelah program berjalan, sekolah mengevaluasi apakah minat baca siswa meningkat atau belum.</p><h2 data-section-id=\"1c1kvpx\" data-start=\"6721\" data-end=\"6770\"> </h2><h2 data-section-id=\"1c1kvpx\" data-start=\"6721\" data-end=\"6770\">8. Aspek yang Dievaluasi dalam Program Sekolah</h2><p data-start=\"6772\" data-end=\"6838\">Beberapa aspek yang dapat dievaluasi dalam program sekolah adalah:</p><ol data-start=\"6840\" data-end=\"7518\"><li data-section-id=\"1np1j7g\" data-start=\"6840\" data-end=\"6930\"><strong data-start=\"6843\" data-end=\"6861\">Tujuan program</strong><br data-start=\"6861\" data-end=\"6864\" />Apakah tujuan program sudah jelas dan sesuai kebutuhan sekolah?</li><li data-section-id=\"rbd6m7\" data-start=\"6932\" data-end=\"7018\"><strong data-start=\"6935\" data-end=\"6958\">Pelaksanaan program</strong><br data-start=\"6958\" data-end=\"6961\" />Apakah program dilaksanakan sesuai jadwal dan rencana?</li><li data-section-id=\"1po5x1y\" data-start=\"7020\" data-end=\"7108\"><strong data-start=\"7023\" data-end=\"7055\">Peserta atau sasaran program</strong><br data-start=\"7055\" data-end=\"7058\" />Apakah program diikuti oleh sasaran yang tepat?</li><li data-section-id=\"1erbfnu\" data-start=\"7110\" data-end=\"7179\"><strong data-start=\"7113\" data-end=\"7137\">Sarana dan prasarana</strong><br data-start=\"7137\" data-end=\"7140\" />Apakah fasilitas pendukung tersedia?</li><li data-section-id=\"avkhj6\" data-start=\"7181\" data-end=\"7270\"><strong data-start=\"7184\" data-end=\"7206\">Dana atau anggaran</strong><br data-start=\"7206\" data-end=\"7209\" />Apakah dana digunakan secara efektif dan sesuai kebutuhan?</li><li data-section-id=\"lmsh94\" data-start=\"7272\" data-end=\"7356\"><strong data-start=\"7275\" data-end=\"7292\">Hasil program</strong><br data-start=\"7292\" data-end=\"7295\" />Apakah program memberikan hasil yang sesuai dengan tujuan?</li><li data-section-id=\"qbp64y\" data-start=\"7358\" data-end=\"7430\"><strong data-start=\"7361\" data-end=\"7381\">Hambatan program</strong><br data-start=\"7381\" data-end=\"7384\" />Apa kendala yang muncul selama pelaksanaan?</li><li data-section-id=\"pfgkc9\" data-start=\"7432\" data-end=\"7518\"><strong data-start=\"7435\" data-end=\"7460\">Tindak lanjut program</strong><br data-start=\"7460\" data-end=\"7463\" />Apa perbaikan yang perlu dilakukan setelah evaluasi?</li></ol><h2 data-section-id=\"ih8kh3\" data-start=\"7525\" data-end=\"7563\"> </h2><h2 data-section-id=\"ih8kh3\" data-start=\"7525\" data-end=\"7563\">9. Perbedaan Supervisi dan Evaluasi</h2><div class=\"TyagGW_tableContainer\"><div class=\"group TyagGW_tableWrapper flex flex-col-reverse w-fit\"><table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"7565\" data-end=\"7993\"><thead data-start=\"7565\" data-end=\"7597\"><tr data-start=\"7565\" data-end=\"7597\"><th class=\"last:pe-10\" data-start=\"7565\" data-end=\"7573\" data-col-size=\"sm\">Aspek</th><th class=\"last:pe-10\" data-start=\"7573\" data-end=\"7585\" data-col-size=\"sm\">Supervisi</th><th class=\"last:pe-10\" data-start=\"7585\" data-end=\"7597\" data-col-size=\"sm\">Evaluasi</th></tr></thead><tbody data-start=\"7612\" data-end=\"7993\"><tr data-start=\"7612\" data-end=\"7681\"><td data-start=\"7612\" data-end=\"7620\" data-col-size=\"sm\">Fokus</td><td data-col-size=\"sm\" data-start=\"7620\" data-end=\"7654\">Pembinaan dan pengawasan proses</td><td data-col-size=\"sm\" data-start=\"7654\" data-end=\"7681\">Penilaian hasil program</td></tr><tr data-start=\"7682\" data-end=\"7767\"><td data-start=\"7682\" data-end=\"7691\" data-col-size=\"sm\">Tujuan</td><td data-col-size=\"sm\" data-start=\"7691\" data-end=\"7732\">Membantu memperbaiki pelaksanaan tugas</td><td data-col-size=\"sm\" data-start=\"7732\" data-end=\"7767\">Mengetahui keberhasilan program</td></tr><tr data-start=\"7768\" data-end=\"7852\"><td data-start=\"7768\" data-end=\"7780\" data-col-size=\"sm\">Pelaksana</td><td data-col-size=\"sm\" data-start=\"7780\" data-end=\"7815\">Kepala sekolah, pengawas sekolah</td><td data-col-size=\"sm\" data-start=\"7815\" data-end=\"7852\">Kepala sekolah, tim sekolah, guru</td></tr><tr data-start=\"7853\" data-end=\"7929\"><td data-start=\"7853\" data-end=\"7861\" data-col-size=\"sm\">Objek</td><td data-col-size=\"sm\" data-start=\"7861\" data-end=\"7896\">Guru, pembelajaran, administrasi</td><td data-col-size=\"sm\" data-start=\"7896\" data-end=\"7929\">Program atau kegiatan sekolah</td></tr><tr data-start=\"7930\" data-end=\"7993\"><td data-start=\"7930\" data-end=\"7938\" data-col-size=\"sm\">Hasil</td><td data-col-size=\"sm\" data-start=\"7938\" data-end=\"7962\">Masukan dan pembinaan</td><td data-col-size=\"sm\" data-start=\"7962\" data-end=\"7993\">Keputusan dan tindak lanjut</td></tr></tbody></table></div></div><p data-start=\"7995\" data-end=\"8133\">Supervisi lebih menekankan pada pembinaan proses, sedangkan evaluasi lebih menekankan pada penilaian hasil dan keberhasilan suatu program.</p>','Supervisi dan Evaluasi Program Sekolah','','publish','open','closed','','supervisi-dan-evaluasi-program-sekolah','','','2026-06-16 11:40:32','2026-06-16 11:40:32','',1216,'http://localhost/wordpress/courses/manajemen-dan-administrasi-sekolah/lessons/supervisi-dan-evaluasi-program-sekolah/',1,'lesson','',0),(1218,1,'2026-06-16 11:40:47','2026-06-16 11:40:47','<h2 data-section-id=\"nujz7r\" data-start=\"9542\" data-end=\"9563\">Latihan </h2><p data-start=\"9565\" data-end=\"9587\">Kerjakan soal berikut.</p><ol data-start=\"9589\" data-end=\"10068\"><li data-section-id=\"sbhzqj\" data-start=\"9589\" data-end=\"9630\">Jelaskan pengertian supervisi sekolah.</li><li data-section-id=\"1ivh9vd\" data-start=\"9631\" data-end=\"9672\">Apa tujuan supervisi dalam pendidikan?</li><li data-section-id=\"3cjpi4\" data-start=\"9673\" data-end=\"9711\">Sebutkan 3 jenis supervisi sekolah.</li><li data-section-id=\"zopwb3\" data-start=\"9712\" data-end=\"9759\">Apa yang dimaksud dengan supervisi akademik?</li></ol>','Latihan 7','','publish','open','closed','','latihan-7-5','','','2026-06-16 11:40:47','2026-06-16 11:40:47','',1216,'http://localhost/wordpress/courses/manajemen-dan-administrasi-sekolah/lessons/latihan-7-5/',2,'lesson','',0),(1219,1,'2026-06-16 11:41:00','2026-06-16 11:41:00','<h2 data-section-id=\"1rrbd2f\" data-start=\"10156\" data-end=\"10174\">Tugas</h2><p data-start=\"10176\" data-end=\"10219\">Jawablah secara singkat pertanyaan berikut:</p><ol data-start=\"10221\" data-end=\"10488\"><li data-section-id=\"sbhzqj\" data-start=\"10221\" data-end=\"10262\">Jelaskan pengertian supervisi sekolah.</li><li data-section-id=\"c9cwsh\" data-start=\"10263\" data-end=\"10314\">Sebutkan 2 contoh kegiatan supervisi di sekolah.</li><li data-section-id=\"1gj0obt\" data-start=\"10315\" data-end=\"10363\">Jelaskan pengertian evaluasi program sekolah.</li><li data-section-id=\"lhru1z\" data-start=\"10364\" data-end=\"10422\">Buatlah 1 contoh program sekolah yang perlu dievaluasi.</li><li data-section-id=\"10h78dw\" data-start=\"10423\" data-end=\"10488\">Tuliskan 1 tindak lanjut dari hasil evaluasi program tersebut.</li></ol>','Tugas 7','','publish','open','closed','','tugas-7-4','','','2026-06-16 11:41:00','2026-06-16 11:41:00','',1216,'http://localhost/wordpress/courses/manajemen-dan-administrasi-sekolah/lessons/tugas-7-4/',3,'lesson','',0),(1220,1,'2026-06-16 11:41:20','2026-06-16 11:41:20','<table class=\"wp-list-table widefat fixed striped table-view-list forms\"><tbody id=\"the-list\" data-wp-lists=\"list:form\"><tr><td class=\"shortcode column-shortcode\" data-colname=\"Shortcode\">[wpforms id=\"1030\"]</td></tr></tbody></table>','Presensi','','publish','open','closed','','presensi-34','','','2026-06-16 11:41:20','2026-06-16 11:41:20','',1216,'http://localhost/wordpress/courses/manajemen-dan-administrasi-sekolah/lessons/presensi-34/',4,'lesson','',0),(1221,1,'2026-06-16 13:27:30','2026-06-16 13:27:30','','Evaluasi','','publish','closed','closed','','pertemuan-8-5','','','2026-06-16 13:27:30','2026-06-16 13:27:30','',1018,'http://localhost/wordpress/topics/pertemuan-8-5/',8,'topics','',0),(1222,1,'2026-06-16 11:49:15','2026-06-16 11:49:15','<h6>About us</h6>		\n			<h2>Amet minim mollit nocn deserunt</h2>		\n		<p>Lorem ipsum dolor sit amet, consectetur adipiscing elit. Maecenas vitae tortor erat. Phasellus elementum at lacus id consequat. Nam volutpat tortor sit amet gravida sodales.</p><p>Integer tempor, quam in fermentum cursus, eros odio feugiat quam, tristique egestas arcu magna non libero. Duis malesuada nisl non mi iaculis scelerisque ut eu urna.</p>		\n													<img width=\"802\"