: 1px solid #e8eef5;\\n  box-shadow: 0 10px 28px rgba(15, 31, 53, 0.08);\\n}\\n\\n.edu-stat-card h3 {\\n  font-size: 34px;\\n  margin: 0;\\n  color: #2563eb;\\n  font-weight: 800;\\n}\\n\\n.edu-stat-card p {\\n  margin: 6px 0 0;\\n  color: #64748b;\\n  font-weight: 600;\\n}\\n\\n.edu-section {\\n  padding: 20px;\\n  margin-bottom: 45px;\\n}\\n\\n.edu-section-title {\\n  margin-bottom: 22px;\\n}\\n\\n.edu-section-title span {\\n  color: #2563eb;\\n  font-size: 14px;\\n  font-weight: 800;\\n  text-transform: uppercase;\\n  letter-spacing: 0.6px;\\n}\\n\\n.edu-section-title h2 {\\n  font-size: 30px;\\n  margin: 6px 0 0;\\n  color: #102033;\\n  font-weight: 800;\\n}\\n\\n.edu-about-box {\\n  background: white;\\n  padding: 28px;\\n  border-radius: 20px;\\n  border: 1px solid #e8eef5;\\n  box-shadow: 0 10px 28px rgba(15, 31, 53, 0.07);\\n}\\n\\n.edu-about-box p {\\n  color: #4b5b70;\\n  margin-bottom: 14px;\\n}\\n\\n.edu-goal-grid,\\n.edu-course-grid,\\n.edu-step-grid {\\n  display: grid;\\n  gap: 20px;\\n}\\n\\n.edu-goal-grid {\\n  grid-template-columns: repeat(4, 1fr);\\n}\\n\\n.edu-course-grid {\\n  grid-template-columns: repeat(3, 1fr);\\n}\\n\\n.edu-step-grid {\\n  grid-template-columns: repeat(3, 1fr);\\n}\\n\\n.edu-goal-card,\\n.edu-course-card,\\n.edu-step-card {\\n  background: white;\\n  border-radius: 20px;\\n  padding: 24px;\\n  border: 1px solid #e8eef5;\\n  box-shadow: 0 10px 28px rgba(15, 31, 53, 0.07);\\n  transition: 0.3s ease;\\n}\\n\\n.edu-goal-card:hover,\\n.edu-course-card:hover,\\n.edu-step-card:hover {\\n  transform: translateY(-5px);\\n  box-shadow: 0 18px 40px rgba(15, 31, 53, 0.12);\\n}\\n\\n.edu-goal-card h3 {\\n  color: #2563eb;\\n  font-size: 26px;\\n  margin: 0 0 10px;\\n}\\n\\n.edu-goal-card p,\\n.edu-course-card p,\\n.edu-step-card p {\\n  color: #4b5b70;\\n  margin: 0;\\n}\\n\\n.edu-course-icon {\\n  width: 54px;\\n  height: 54px;\\n  background: #eff6ff;\\n  border-radius: 16px;\\n  display: flex;\\n  align-items: center;\\n  justify-con