-template-columns: repeat(2, 1fr);\n  gap: 12px;\n}\n\n.edu-mini-list span {\n  background: #ffffff;\n  color: #1d4ed8;\n  padding: 13px;\n  border-radius: 14px;\n  font-weight: 700;\n  text-align: center;\n  box-shadow: 0 10px 25px rgba(15, 23, 42, 0.12);\n}\n\n.edu-hero-img {\n  display: block;\n  width: min(85%, 900px);\n  height: auto;\n  max-height: 360px;\n  object-fit: contain;\n  margin: -30px auto 60px;\n  border-radius: 24px;\n  box-shadow: 0 22px 55px rgba(0, 0, 0, 0.16);\n  border: 6px solid #ffffff;\n  background: #ffffff;\n}\n\n.edu-section {\n  padding: 70px 8%;\n}\n\n.edu-section-title {\n  text-align: center;\n  margin-bottom: 42px;\n}\n\n.edu-section-title span {\n  display: inline-block;\n  color: #2563eb;\n  font-weight: 700;\n  font-size: 15px;\n  margin-bottom: 8px;\n  text-transform: uppercase;\n  letter-spacing: 1px;\n}\n\n.edu-section-title h2 {\n  font-size: 36px;\n  color: #0f172a;\n  margin: 0;\n  font-weight: 800;\n}\n\n.edu-about-box {\n  max-width: 950px;\n  margin: auto;\n  background: #ffffff;\n  padding: 38px;\n  border-radius: 26px;\n  box-shadow: 0 18px 45px rgba(15, 23, 42, 0.08);\n  border-left: 7px solid #2563eb;\n}\n\n.edu-about-box p {\n  font-size: 17px;\n  line-height: 1.9;\n  color: #475569;\n  margin: 0 0 16px;\n}\n\n.edu-about-box p:last-child {\n  margin-bottom: 0;\n}\n\n.edu-goal-grid {\n  display: grid;\n  grid-template-columns: repeat(4, 1fr);\n  gap: 24px;\n}\n\n.edu-goal-card {\n  background: #ffffff;\n  padding: 30px;\n  border-radius: 24px;\n  box-shadow: 0 16px 42px rgba(15, 23, 42, 0.08);\n  transition: 0.3s ease;\n  border: 1px solid #e2e8f0;\n}\n\n.edu-goal-card:hover {\n  transform: translateY(-8px);\n  box-shadow: 0 24px 55px rgba(37, 99, 235, 0.16);\n  border-color: #bfdbfe;\n}\n\n.edu-goal-card h3 {\n  font-size: 34px;\n  color: #2563eb;\n  margin: 0 0 14px;\n  font-weight: 800;\n}\n\n.edu-goal-card p {\n  font-size: 15px;\n  line-height: 1.7;\n  color: #475569;\n  margin: 0;\n}\n\n.edu-course-grid {\n  display: grid;\n  grid-template-columns: repeat(5, 1fr);\n  gap: 24px;\n}\n\n.edu-course-card {\n  background: #ffffff;\n  padding: 30px 24px;\n  border-radius: 26px;\n  box-shadow: 0 18px 45px rgba(15, 23, 42, 0.08);\n  transition: 0.3s ease;\n  border: 1px solid #e2e8f0;\n  display: flex;\n  flex-direction: column;\n  min-height: 330px;\n}\n\n.edu-course-card:hover {\n  transform: translateY(-8px);\n  box-shadow: 0 25px 60px rgba(37, 99, 235, 0.18);\n  border-color: #93c5fd;\n}\n\n.edu-course-icon {\n  width: 62px;\n  height: 62px;\n  background: #dbeafe;\n  color: #1d4ed8;\n  border-radius: 18px;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  font-size: 32px;\n  margin-bottom: 18px;\n}\n\n.edu-course-card h3 {\n  font-size: 20px;\n  color: #0f172a;\n  margin: 0 0 12px;\n  font-weight: 800;\n}\n\n.edu-course-card p {\n  font-size: 14.5px;\n  line-height: 1.7;\n  color: #475569;\n  margin-bottom: 20px;\n  flex: 1;\n}\n\n.edu-course-card a {\n  display: inline-block;\n  text-align: center;\n  padding: 12px 18px;\n  background: #2563eb;\n  color: #ffffff;\n  text-decoration: none;\n  border-radius: 14px;\n  font-size: 14px;\n  font-weight: 700;\n  transition: 0.3s ease;\n}\n\n.edu-course-card a:hover {\n  background: #1d4ed8;\n  color: #ffffff;\n}\n\n.edu-step-grid {\n  display: grid;\n  grid-template-columns: repeat(3, 1fr);\n  gap: 26px;\n}\n\n.edu-step-card {\n  background: #ffffff;\n  padding: 32px;\n  border-radius: 26px;\n  box-shadow: 0 18px 45px rgba(15, 23, 42, 0.08);\n  text-align: center;\n  transition: 0.3s ease;\n  border: 1px solid #e2e8f0;\n}\n\n.edu-step-card:hover {\n  transform: translateY(-8px);\n  box-shadow: 0 25px 60px rgba(37, 99, 235, 0.18);\n  border-color: #93c5fd;\n}\n\n.edu-step-card span {\n  width: 58px;\n  height: 58px;\n  background: #2563eb;\n  color: #ffffff;\n  border-radius: 50%;\n  display: inline-flex;\n  align-items: center;\n  justify-content: center;\n  font-size: 22px;\n  font-weight: 800;\n  margin-bottom: 18px;\n}\n\n.edu-step-card h3 {\n  font-size: 21px;\n  color: #0f172a;\n  margin: 0 0 12px;\n  font-weight: 800;\n}\n\n.edu-step-card p {\n  font-size: 15px;\n  line-height: 1.7;\n  color: #475569;\n  margin: 0;\n}\n\n@media (max-width: 1100px) {\n  .edu-hero {\n    grid-template-columns: 1fr;\n    padding: 75px 6%;\n  }\n\n  .edu-hero h1 {\n    font-size: 42px;\n  }\n\n  .edu-goal-grid {\n    grid-template-columns: repeat(2, 1fr);\n  }\n\n  .edu-course-grid {\n    grid-template-columns: repeat(2, 1fr);\n  }\n\n  .edu-step-grid {\n    grid-template-columns: 1fr;\n  }\n}\n\n@media (max-width: 700px) {\n  .edu-hero {\n    padding: 60px 24px;\n    border-radius: 0 0 28px 28px;\n  }\n\n  .edu-hero h1 {\n    font-size: 34px;\n  }\n\n  .edu-hero p {\n    font-size: 15.5px;\n  }\n\n  .edu-hero-card {\n    padding: 26px;\n  }\n\n  .edu-hero-img {\n    width: 90%;\n    height: 230px;\n    margin: -30px auto 45px;\n    border-radius: 22px;\n    border: 5px solid #ffffff;\n  }\n\n  .edu-section {\n    padding: 50px 24px;\n  }\n\n  .edu-section-title h2 {\n    font-size: 28px;\n  }\n\n  .edu-about-box {\n    padding: 26px;\n  }\n\n  .edu-goal-grid,\n  .edu-course-grid,\n  .edu-step-grid {\n    grid-template-columns: 1fr;\n  }\n\n  .edu-course-card {\n    min-height: auto;\n  }\n\n  .edu-hero-buttons {\n    flex-direction: column;\n  }\n\n  .edu-btn-primary,\n  .edu-btn-secondary {\n    text-align: center;\n    width: 100%;\n  }\n}\n\n\n</style>\n\n<div class=\"edu-home\">\n\n  <section class=\"edu-hero\">\n    <div class=\"edu-hero-content\">\n      <span class=\"edu-badge\">Learning Management System</span>\n      <h1>Selamat Datang di LMS EduClass</h1>\n      <p>\n        EduClass adalah Learning Management System berbasis WordPress yang dibuat untuk mendukung proses pembelajaran online melalui localhost. LMS ini menyediakan berbagai mata kuliah yang dilengkapi dengan materi, latihan, penugasan, dan presensi pada setiap pertemuan.\n      </p>\n\n      <div class=\"edu-hero-buttons\">\n        <a href=\"/wordpress/courses\" class=\"edu-btn-primary\">Lihat Mata Kuliah</a>\n        <a href=\"#tentang-lms\" class=\"edu-btn-secondary\">Tentang LMS</a>\n      </div>\n    </div>\n\n    <div class=\"edu-hero-card\">\n      <h3>EduClass LMS</h3>\n      <p>Platform pembelajaran digital untuk mahasiswa.</p>\n      <div class=\"edu-mini-list\">\n        <span>Materi</span>\n        <span>Latihan</span>\n        <span>Tugas</span>\n        <span>Presensi</span>\n      </div>\n    </div>\n  </section>\n\n <img src=\"http://localhost/wordpress/wp-content/uploads/2026/06/unlam.jpeg\" class=\"edu-hero-img\" alt=\"Foto LMS\">\n  <section class=\"edu-section\" id=\"tentang-lms\">\n    <div class=\"edu-section-title\">\n      <span>Tentang LMS</span>\n      <h2>Deskripsi LMS EduClass</h2>\n    </div>\n\n    <div class=\"edu-about-box\">\n      <p>\n        Melalui LMS ini, mahasiswa dapat mengakses materi pembelajaran secara terstruktur, mengikuti latihan, mengerjakan tugas, serta mengisi daftar hadir sesuai dengan mata kuliah yang dipilih.\n      </p>\n\n      <p>\n        LMS EduClass dibuat sebagai media pembelajaran digital yang membantu dosen dan mahasiswa dalam proses pembelajaran berbasis teknologi.\n      </p>\n    </div>\n  </section>\n\n  <section class=\"edu-section\">\n    <div class=\"edu-section-title\">\n      <span>Tujuan</span>\n      <h2>Tujuan Pengembangan LMS</h2>\n    </div>\n\n    <div class=\"edu-goal-grid\">\n      <div class=\"edu-goal-card\">\n        <h3>01</h3>\n        <p>Menyediakan media pembelajaran digital yang mudah digunakan.</p>\n      </div>\n\n      <div class=\"edu-goal-card\">\n        <h3>02</h3>\n        <p>Memudahkan mahasiswa mengakses materi kuliah secara online.</p>\n      </div>\n\n      <div class=\"edu-goal-card\">\n        <h3>03</h3>\n        <p>Membantu dosen mengelola materi, tugas, latihan, dan presensi.</p>\n      </div>\n\n      <div class=\"edu-goal-card\">\n        <h3>04</h3>\n        <p>Melatih penggunaan WordPress sebagai platform e-learning.</p>\n      </div>\n    </div>\n  </section>\n\n  <section class=\"edu-section\" id=\"daftar-matkul\">\n  <div class=\"edu-section-title\">\n    <span>Daftar Mata Kuliah</span>\n    <h2>Mata Kuliah yang Tersedia</h2>\n  </div>\n\n  <div class=\"edu-course-grid\">\n\n    <div class=\"edu-course-card\">\n      <div class=\"edu-course-icon\">💼</div>\n      <h3>Kewirausahaan</h3>\n      <p>Mempelajari konsep usaha, peluang bisnis, perencanaan usaha, pemasaran, dan pengelolaan keuangan.</p>\n      <a href=\"courses/kewirausahaan/\">Lihat Materi</a>\n    </div>\n\n    <div class=\"edu-course-card\">\n      <div class=\"edu-course-icon\">🇮🇩</div>\n      <h3>Pancasila</h3>\n      <p>Mempelajari nilai-nilai Pancasila sebagai dasar negara dan penerapannya dalam kehidupan sehari-hari.</p>\n      <a href=\"courses/pancasila/\">Lihat Materi</a>\n    </div>\n\n    <div class=\"edu-course-card\">\n      <div class=\"edu-course-icon\">📐</div>\n      <h3>Matematika Dasar</h3>\n      <p>Mempelajari konsep dasar matematika seperti bilangan, aljabar, fungsi, geometri, dan statistika.</p>\n      <a href=\"courses/matematika-dasar/\">Lihat Materi</a>\n    </div>\n\n    <div class=\"edu-course-card\">\n      <div class=\"edu-course-icon\">👨‍🏫</div>\n      <h3>Profesi Kependidikan</h3>\n      <p>Mempelajari peran, tugas, kompetensi, dan etika seorang pendidik profesional.</p>\n      <a href=\"courses/profesi-kependidikan/\">Lihat Materi</a>\n    </div>\n\n    <div class=\"edu-course-card\">\n      <div class=\"edu-course-icon\">🏫</div>\n      <h3>Manajemen dan Administrasi Sekolah</h3>\n      <p>Mempelajari pengelolaan sekolah, administrasi pendidikan, kepemimpinan, dan layanan pendidikan.</p>\n      <a href=\"courses/manajemen-dan-administrasi-sekolah/\">Lihat Materi</a>\n    </div>\n\n  </div>\n</section>\n\n  <section class=\"edu-section\">\n    <div class=\"edu-section-title\">\n      <span>Alur Penggunaan</span>\n      <h2>Cara Menggunakan LMS</h2>\n    </div>\n\n    <div class=\"edu-step-grid\">\n      <div class=\"edu-step-card\">\n        <span>1</span>\n        <h3>Pilih Mata Kuliah</h3>\n        <p>Mahasiswa memilih mata kuliah yang tersedia pada LMS.</p>\n      </div>\n\n      <div class=\"edu-step-card\">\n        <span>2</span>\n        <h3>Pelajari Materi</h3>\n        <p>Mahasiswa membaca materi, mengerjakan latihan, dan memahami isi pembelajaran.</p>\n      </div>\n\n      <div class=\"edu-step-card\">\n        <span>3</span>\n        <h3>Kumpulkan Tugas</h3>\n        <p>Mahasiswa mengisi presensi dan mengumpulkan tugas sesuai pertemuan.</p>\n      </div>\n    </div>\n  </section>\n\n</div>\n<!-- /wp:html -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->','Beranda','','inherit','closed','closed','','1052-autosave-v1','','','2026-06-16 15:49:10','2026-06-16 15:49:10','',1052,'http://localhost/wordpress/?p=1283',0,'revision','',0),(1284,1,'2026-06-16 15:40:49','2026-06-16 15:40:49','<!-- wp:html -->\n<style data-wp-block-html=\"css\">\n/* =========================\n   EDUCLASS LMS - BLUE CLEAN\n========================= */\n\n.edu-home {\n  font-family: \"Poppins\", Arial, sans-serif;\n  color: #1e293b;\n  background: #f8fbff;\n  overflow: hidden;\n}\n\n/* HERO */\n.edu-hero {\n  min-height: 520px;\n  padding: 90px 8%;\n  display: grid;\n  grid-template-columns: 1.3fr 0.7fr;\n  gap: 40px;\n  align-items: center;\n  background: linear-gradient(135deg, #1d4ed8, #2563eb, #38bdf8);\n  color: #ffffff;\n  border-radius: 0 0 38px 38px;\n  position: relative;\n}\n\n.edu-hero-content {\n  max-width: 720px;\n  z-index: 2;\n}\n\n.edu-badge {\n  display: inline-block;\n  padding: 9px 18px;\n  background: rgba(255, 255, 255, 0.18);\n  color: #ffffff;\n  border: 1px solid rgba(255, 255, 255, 0.35);\n  border-radius: 999px;\n  font-size: 14px;\n  font-weight: 600;\n  margin-bottom: 18px;\n}\n\n.edu-hero h1 {\n  font-size: 52px;\n  line-height: 1.15;\n  margin: 0 0 20px;\n  font-weight: 800;\n  color: #ffffff;\n}\n\n.edu-hero p {\n  font-size: 17px;\n  line-height: 1.8;\n  color: #eff6ff;\n  margin-bottom: 30px;\n}\n\n/* BUTTON */\n.edu-hero-buttons {\n  display: flex;\n  gap: 16px;\n  flex-wrap: wrap;\n}\n\n.edu-btn-primary,\n.edu-btn-secondary {\n  display: inline-block;\n  padding: 14px 24px;\n  border-radius: 14px;\n  font-size: 15px;\n  font-weight: 700;\n  text-decoration: none;\n  transition: 0.3s ease;\n}\n\n.edu-btn-primary {\n  background: #ffffff;\n  color: #1d4ed8;\n}\n\n.edu-btn-primary:hover {\n  background: #dbeafe;\n  color: #1e40af;\n  transform: translateY(-3px);\n}\n\n.edu-btn-secondary {\n  background: transparent;\n  color: #ffffff;\n  border: 2px solid rgba(255, 255, 255, 0.75);\n}\n\n.edu-btn-secondary:hover {\n  background: rgba(255, 255, 255, 0.16);\n  color: #ffffff;\n  transform: translateY(-3px);\n}\n\n/* HERO CARD */\n.edu-hero-card {\n  background: rgba(255, 255, 255, 0.16);\n  border: 1px solid rgba(255, 255, 255, 0.32);\n  backdrop-filter: blur(14px);\n  border-radius: 28px;\n  padding: 34px;\n  box-shadow: 0 25px 60px rgba(15, 23, 42, 0.18);\n}\n\n.edu-hero-card h3 {\n  font-size: 28px;\n  margin: 0 0 10px;\n  color: #ffffff;\n}\n\n.edu-hero-card p {\n  font-size: 15px;\n  margin-bottom: 22px;\n  color: #eff6ff;\n}\n\n.edu-mini-list {\n  display: grid;\n  grid-template-columns: repeat(2, 1fr);\n  gap: 12px;\n}\n\n.edu-mini-list span {\n  background: #ffffff;\n  color: #1d4ed8;\n  padding: 13px;\n  border-radius: 14px;\n  font-weight: 700;\n  text-align: center;\n  box-shadow: 0 10px 25px rgba(15, 23, 42, 0.12);\n}\n\n/* HERO IMAGE */\n.edu-hero-img {\n  display: block;\n  width: min(85%, 900px);\n  height: auto;\n  max-height: 360px;\n  object-fit: contain;\n  margin: -30px auto 60px;\n  border-radius: 24px;\n  box-shadow: 0 22px 55px rgba(0, 0, 0, 0.16);\n  border: 6px solid #ffffff;\n  background: #ffffff;\n}\n\n/* SECTION */\n.edu-section {\n  padding: 70px 8%;\n}\n\n.edu-section-title {\n  text-align: center;\n  margin-bottom: 42px;\n}\n\n.edu-section-title span {\n  display: inline-block;\n  color: #2563eb;\n  font-weight: 700;\n  font-size: 15px;\n  margin-bottom: 8px;\n  text-transform: uppercase;\n  letter-spacing: 1px;\n}\n\n.edu-section-title h2 {\n  font-size: 36px;\n  color: #0f172a;\n  margin: 0;\n  font-weight: 800;\n}\n\n/* ABOUT */\n.edu-about-box {\n  max-width: 950px;\n  margin: auto;\n  background: #ffffff;\n  padding: 38px;\n  border-radius: 26px;\n  box-shadow: 0 18px 45px rgba(15, 23, 42, 0.08);\n  border-left: 7px solid #2563eb;\n}\n\n.edu-about-box p {\n  font-size: 17px;\n  line-height: 1.9;\n  color: #475569;\n  margin: 0 0 16px;\n}\n\n.edu-about-box p:last-child {\n  margin-bottom: 0;\n}\n\n/* GOAL */\n.edu-goal-grid {\n  display: grid;\n  grid-template-columns: repeat(4, 1fr);\n  gap: 24px;\n}\n\n.edu-goal-card {\n  background: #ffffff;\n  padding: 30px;\n  border-radius: 24px;\n  box-shadow: 0 16px 42px rgba(15, 23, 42, 0.08);\n  transition: 0.3s ease;\n  border: 1px solid #e2e8f0;\n}\n\n.edu-goal-card:hover {\n  transform: translateY(-8px);\n  box-shadow: 0 24px 55px rgba(37, 99, 235, 0.16);\n  border-color: #bfdbfe;\n}\n\n.edu-goal-card h3 {\n  font-size: 34px;\n  color: #2563eb;\n  margin: 0 0 14px;\n  font-weight: 800;\n}\n\n.edu-goal-card p {\n  font-size: 15px;\n  line-height: 1.7;\n  color: #475569;\n  margin: 0;\n}\n\n/* COURSE */\n.edu-course-grid {\n  display: grid;\n  grid-template-columns: repeat(5, 1fr);\n  gap: 24px;\n}\n\n.edu-course-card {\n  background: #ffffff;\n  padding: 30px 24px;\n  border-radius: 26px;\n  box-shadow: 0 18px 45px rgba(15, 23, 42, 0.08);\n  transition: 0.3s ease;\n  border: 1px solid #e2e8f0;\n  display: flex;\n  flex-direction: column;\n  min-height: 330px;\n}\n\n.edu-course-card:hover {\n  transform: translateY(-8px);\n  box-shadow: 0 25px 60px rgba(37, 99, 235, 0.18);\n  border-color: #93c5fd;\n}\n\n.edu-course-icon {\n  width: 62px;\n  height: 62px;\n  background: #dbeafe;\n  color: #1d4ed8;\n  border-radius: 18px;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  font-size: 32px;\n  margin-bottom: 18px;\n}\n\n.edu-course-card h3 {\n  font-size: 20px;\n  color: #0f172a;\n  margin: 0 0 12px;\n  font-weight: 800;\n}\n\n.edu-course-card p {\n  font-size: 14.5px;\n  line-height: 1.7;\n  color: #475569;\n  margin-bottom: 20px;\n  flex: 1;\n}\n\n.edu-course-card a {\n  display: inline-block;\n  text-align: center;\n  padding: 12px 18px;\n  background: #2563eb;\n  color: #ffffff;\n  text-decoration: none;\n  border-radius: 14px;\n  font-size: 14px;\n  font-weight: 700;\n  transition: 0.3s ease;\n}\n\n.edu-course-card a:hover {\n  background: #1d4ed8;\n  color: #ffffff;\n}\n\n/* STEP */\n.edu-step-grid {\n  display: grid;\n  grid-template-columns: repeat(3, 1fr);\n  gap: 26px;\n}\n\n.edu-step-card {\n  background: #ffffff;\n  padding: 32px;\n  border-radius: 26px;\n  box-shadow: 0 18px 45px rgba(15, 23, 42, 0.08);\n  text-align: center;\n  transition: 0.3s ease;\n  border: 1px solid #e2e8f0;\n}\n\n.edu-step-card:hover {\n  transform: translateY(-8px);\n  box-shadow: 0 25px 60px rgba(37, 99, 235, 0.18);\n  border-color: #93c5fd;\n}\n\n.edu-step-card span {\n  width: 58px;\n  height: 58px;\n  background: #2563eb;\n  color: #ffffff;\n  border-radius: 50%;\n  display: inline-flex;\n  align-items: center;\n  justify-content: center;\n  font-size: 22px;\n  font-weight: 800;\n  margin-bottom: 18px;\n}\n\n.edu-step-card h3 {\n  font-size: 21px;\n  color: #0f172a;\n  margin: 0 0 12px;\n  font-weight: 800;\n}\n\n.edu-step-card p {\n  font-size: 15px;\n  line-height: 1.7;\n  color: #475569;\n  margin: 0;\n}\n\n/* RESPONSIVE */\n@media (max-width: 1100px) {\n  .edu-hero {\n    grid-template-columns: 1fr;\n    padding: 75px 6%;\n  }\n\n  .edu-hero h1 {\n    font-size: 42px;\n  }\n\n  .edu-goal-grid {\n    grid-template-columns: repeat(2, 1fr);\n  }\n\n  .edu-course-grid {\n    grid-template-columns: repeat(2, 1fr);\n  }\n\n  .edu-step-grid {\n    grid-template-columns: 1fr;\n  }\n}\n\n@media (max-width: 700px) {\n  .edu-hero {\n    padding: 60px 24px;\n    border-radius: 0 0 28px 28px;\n  }\n\n  .edu-hero h1 {\n    font-size: 34px;\n  }\n\n  .edu-hero p {\n    font-size: 15.5px;\n  }\n\n  .edu-hero-card {\n    padding: 26px;\n  }\n\n  .edu-hero-img {\n    width: 90%;\n    height: 230px;\n    margin: -30px auto 45px;\n    border-radius: 22px;\n    border: 5px solid #ffffff;\n  }\n\n  .edu-section {\n    padding: 50px 24px;\n  }\n\n  .edu-section-title h2 {\n    font-size: 28px;\n  }\n\n  .edu-about-box {\n    padding: 26px;\n  }\n\n  .edu-goal-grid,\n  .edu-course-grid,\n  .edu-step-grid {\n    grid-template-columns: 1fr;\n  }\n\n  .edu-course-card {\n    min-height: auto;\n  }\n\n  .edu-hero-buttons {\n    flex-direction: column;\n  }\n\n  .edu-btn-primary,\n  .edu-btn-secondary {\n    text-align: center;\n    width: 100%;\n  }\n}\n</style>\n\n<div class=\"edu-home\">\n\n  <section class=\"edu-hero\">\n    <div class=\"edu-hero-content\">\n      <span class=\"edu-badge\">Learning Management System</span>\n      <h1>Selamat Datang di LMS EduClass</h1>\n      <p>\n        EduClass adalah Learning Management System berbasis WordPress yang dibuat untuk mendukung proses pembelajaran online melalui localhost. LMS ini menyediakan berbagai mata kuliah yang dilengkapi dengan materi, latihan, penugasan, dan presensi pada setiap pertemuan.\n      </p>\n\n      <div class=\"edu-hero-buttons\">\n        <a href=\"#daftar-matkul\" class=\"edu-btn-primary\">Lihat Mata Kuliah</a>\n        <a href=\"#tentang-lms\" class=\"edu-btn-secondary\">Tentang LMS</a>\n      </div>\n    </div>\n\n    <div class=\"edu-hero-card\">\n      <h3>EduClass LMS</h3>\n      <p>Platform pembelajaran digital untuk mahasiswa.</p>\n      <div class=\"edu-mini-list\">\n        <span>Materi</span>\n        <span>Latihan</span>\n        <span>Tugas</span>\n        <span>Presensi</span>\n      </div>\n    </div>\n  </section>\n\n <img src=\"http://localhost/wordpress/wp-content/uploads/2026/06/unlam.jpeg\" class=\"edu-hero-img\" alt=\"Foto LMS\">\n  <section class=\"edu-section\" id=\"tentang-lms\">\n    <div class=\"edu-section-title\">\n      <span>Tentang LMS</span>\n      <h2>Deskripsi LMS EduClass</h2>\n    </div>\n\n    <div class=\"edu-about-box\">\n      <p>\n        Melalui LMS ini, mahasiswa dapat mengakses materi pembelajaran secara terstruktur, mengikuti latihan, mengerjakan tugas, serta mengisi daftar hadir sesuai dengan mata kuliah yang dipilih.\n      </p>\n\n      <p>\n        LMS EduClass dibuat sebagai media pembelajaran digital yang membantu dosen dan mahasiswa dalam proses pembelajaran berbasis teknologi.\n      </p>\n    </div>\n  </section>\n\n  <section class=\"edu-section\">\n    <div class=\"edu-section-title\">\n      <span>Tujuan</span>\n      <h2>Tujuan Pengembangan LMS</h2>\n    </div>\n\n    <div class=\"edu-goal-grid\">\n      <div class=\"edu-goal-card\">\n        <h3>01</h3>\n        <p>Menyediakan media pembelajaran digital yang mudah digunakan.</p>\n      </div>\n\n      <div class=\"edu-goal-card\">\n        <h3>02</h3>\n        <p>Memudahkan mahasiswa mengakses materi kuliah secara online.</p>\n      </div>\n\n      <div class=\"edu-goal-card\">\n        <h3>03</h3>\n        <p>Membantu dosen mengelola materi, tugas, latihan, dan presensi.</p>\n      </div>\n\n      <div class=\"edu-goal-card\">\n        <h3>04</h3>\n        <p>Melatih penggunaan WordPress sebagai platform e-learning.</p>\n      </div>\n    </div>\n  </section>\n\n  <section class=\"edu-section\" id=\"daftar-matkul\">\n  <div class=\"edu-section-title\">\n    <span>Daftar Mata Kuliah</span>\n    <h2>Mata Kuliah yang Tersedia</h2>\n  </div>\n\n  <div class=\"edu-course-grid\">\n\n    <div class=\"edu-course-card\">\n      <div class=\"edu-course-icon\">💼</div>\n      <h3>Kewirausahaan</h3>\n      <p>Mempelajari konsep usaha, peluang bisnis, perencanaan usaha, pemasaran, dan pengelolaan keuangan.</p>\n      <a href=\"courses/kewirausahaan/\">Lihat Materi</a>\n    </div>\n\n    <div class=\"edu-course-card\">\n      <div class=\"edu-course-icon\">🇮🇩</div>\n      <h3>Pancasila</h3>\n      <p>Mempelajari nilai-nilai Pancasila sebagai dasar negara dan penerapannya dalam kehidupan sehari-hari.</p>\n      <a href=\"courses/pancasila/\">Lihat Materi</a>\n    </div>\n\n    <div class=\"edu-course-card\">\n      <div class=\"edu-course-icon\">📐</div>\n      <h3>Matematika Dasar</h3>\n      <p>Mempelajari konsep dasar matematika seperti bilangan, aljabar, fungsi, geometri, dan statistika.</p>\n      <a href=\"courses/matematika-dasar/\">Lihat Materi</a>\n    </div>\n\n    <div class=\"edu-course-card\">\n      <div class=\"edu-course-icon\">👨‍🏫</div>\n      <h3>Profesi Kependidikan</h3>\n      <p>Mempelajari peran, tugas, kompetensi, dan etika seorang pendidik profesional.</p>\n      <a href=\"courses/profesi-kependidikan/\">Lihat Materi</a>\n    </div>\n\n    <div class=\"edu-course-card\">\n      <div class=\"edu-course-icon\">🏫</div>\n      <h3>Manajemen dan Administrasi Sekolah</h3>\n      <p>Mempelajari pengelolaan sekolah, administrasi pendidikan, kepemimpinan, dan layanan pendidikan.</p>\n      <a href=\"courses/manajemen-dan-administrasi-sekolah/\">Lihat Materi</a>\n    </div>\n\n  </div>\n</section>\n\n  <section class=\"edu-section\">\n    <div class=\"edu-section-title\">\n      <span>Alur Penggunaan</span>\n      <h2>Cara Menggunakan LMS</h2>\n    </div>\n\n    <div class=\"edu-step-grid\">\n      <div class=\"edu-step-card\">\n        <span>1</span>\n        <h3>Pilih Mata Kuliah</h3>\n        <p>Mahasiswa memilih mata kuliah yang tersedia pada LMS.</p>\n      </div>\n\n      <div class=\"edu-step-card\">\n        <span>2</span>\n        <h3>Pelajari Materi</h3>\n        <p>Mahasiswa membaca materi, mengerjakan latihan, dan memahami isi pembelajaran.</p>\n      </div>\n\n      <div class=\"edu-step-card\">\n        <span>3</span>\n        <h3>Kumpulkan Tugas</h3>\n        <p>Mahasiswa mengisi presensi dan mengumpulkan tugas sesuai pertemuan.</p>\n      </div>\n    </div>\n  </section>\n\n</div>\n<!-- /wp:html -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->','Beranda','','inherit','closed','closed','','1052-revision-v1','','','2026-06-16 15:40:49','2026-06-16 15:40:49','',1052,'http://localhost/wordpress/?p=1284',0,'revision','',0),(1285,1,'2026-06-16 15:49:16','2026-06-16 15:49:16','<!-- wp:html -->\n<style data-wp-block-html=\"css\">\n\n.edu-home {\n  font-family: \"Poppins\", Arial, sans-serif;\n  color: #1e293b;\n  background: #f8fbff;\n  overflow: hidden;\n}\n\n.edu-hero {\n  min-height: 520px;\n  padding: 90px 8%;\n  display: grid;\n  grid-template-columns: 1.3fr 0.7fr;\n  gap: 40px;\n  align-items: center;\n  background: linear-gradient(135deg, #1d4ed8, #2563eb, #38bdf8);\n  color: #ffffff;\n  border-radius: 0 0 38px 38px;\n  position: relative;\n}\n\n.edu-hero-content {\n  max-width: 720px;\n  z-index: 2;\n}\n\n.edu-badge {\n  display: inline-block;\n  padding: 9px 18px;\n  background: rgba(255, 255, 255, 0.18);\n  color: #ffffff;\n  border: 1px solid rgba(255, 255, 255, 0.35);\n  border-radius: 999px;\n  font-size: 14px;\n  font-weight: 600;\n  margin-bottom: 18px;\n}\n\n.edu-hero h1 {\n  font-size: 52px;\n  line-height: 1.15;\n  margin: 0 0 20px;\n  font-weight: 800;\n  color: #ffffff;\n}\n\n.edu-hero p {\n  font-size: 17px;\n  line-height: 1.8;\n  color: #eff6ff;\n  margin-bottom: 30px;\n}\n\n.edu-hero-buttons {\n  display: flex;\n  gap: 16px;\n  flex-wrap: wrap;\n}\n\n.edu-btn-primary,\n.edu-btn-secondary {\n  display: inline-block;\n  padding: 14px 24px;\n  border-radius: 14px;\n  font-size: 15px;\n  font-weight: 700;\n  text-decoration: none;\n  transition: 0.3s ease;\n}\n\n.edu-btn-primary {\n  background: #ffffff;\n  color: #1d4ed8;\n}\n\n.edu-btn-primary:hover {\n  background: #dbeafe;\n  color: #1e40af;\n  transform: translateY(-3px);\n}\n\n.edu-btn-secondary {\n  background: transparent;\n  color: #ffffff;\n  border: 