grid-template-columns: repeat(4, 1fr);\n  gap: 24px;\n}\n\n.edu-goal-card {\n  background: #ffffff;\n  padding: 30px;\n  border-radius: 24px;\n  box-shadow: 0 16px 42px rgba(15, 23, 42, 0.08);\n  transition: 0.3s ease;\n  border: 1px solid #e2e8f0;\n}\n\n.edu-goal-card:hover {\n  transform: translateY(-8px);\n  box-shadow: 0 24px 55px rgba(37, 99, 235, 0.16);\n  border-color: #bfdbfe;\n}\n\n.edu-goal-card h3 {\n  font-size: 34px;\n  color: #2563eb;\n  margin: 0 0 14px;\n  font-weight: 800;\n}\n\n.edu-goal-card p {\n  font-size: 15px;\n  line-height: 1.7;\n  color: #475569;\n  margin: 0;\n}\n\n.edu-course-grid {\n  display: grid;\n  grid-template-columns: repeat(5, 1fr);\n  gap: 24px;\n}\n\n.edu-course-card {\n  background: #ffffff;\n  padding: 30px 24px;\n  border-radius: 26px;\n  box-shadow: 0 18px 45px rgba(15, 23, 42, 0.08);\n  transition: 0.3s ease;\n  border: 1px solid #e2e8f0;\n  display: flex;\n  flex-direction: column;\n  min-height: 330px;\n}\n\n.edu-course-card:hover {\n  transform: translateY(-8px);\n  box-shadow: 0 25px 60px rgba(37, 99, 235, 0.18);\n  border-color: #93c5fd;\n}\n\n.edu-course-icon {\n  width: 62px;\n  height: 62px;\n  background: #dbeafe;\n  color: #1d4ed8;\n  border-radius: 18px;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  font-size: 32px;\n  margin-bottom: 18px;\n}\n\n.edu-course-card h3 {\n  font-size: 20px;\n  color: #0f172a;\n  margin: 0 0 12px;\n  font-weight: 800;\n}\n\n.edu-course-card p {\n  font-size: 14.5px;\n  line-height: 1.7;\n  color: #475569;\n  margin-bottom: 20px;\n  flex: 1;\n}\n\n.edu-course-card a {\n  display: inline-block;\n  text-align: center;\n  padding: 12px 18px;\n  background: #2563eb;\n  color: #ffffff;\n  text-decoration: none;\n  border-radius: 14px;\n  font-size: 14px;\n  font-weight: 700;\n  transition: 0.3s ease;\n}\n\n.edu-course-card a:hover {\n  background: #1d4ed8;\n  color: #ffffff;\n}\n\n.edu-step-grid {\n  display: grid;\n  grid-template-columns: repeat(3, 1fr);\n  gap: 26px;\n}\n\n.edu-step-card {\n  background: #ffffff;\n  padding: 32px;\n  border-radius: 26px;\n  box-shadow: 0 18px 45px rgba(15, 23, 42, 0.08);\n  text-align: center;\n  transition: 0.3s ease;\n  border: 1px solid #e2e8f0;\n}\n\n.edu-step-card:hover {\n  transform: translateY(-8px);\n  box-shadow: 0 25px 60px rgba(37, 99, 235, 0.18);\n  border-color: #93c5fd;\n}\n\n.edu-step-card span {\n  width: 58px;\n  height: 58px;\n  background: #2563eb;\n  color: #ffffff;\n  border-radius: 50%;\n  display: inline-flex;\n  align-items: center;\n  justify-content: center;\n  font-size: 22px;\n  font-weight: 800;\n  margin-bottom: 18px;\n}\n\n.edu-step-card h3 {\n  font-size: 21px;\n  color: #0f172a;\n  margin: 0 0 12px;\n  font-weight: 800;\n}\n\n.edu-step-card p {\n  font-size: 15px;\n  line-height: 1.7;\n  color: #475569;\n  margin: 0;\n}\n\n@media (max-width: 1100px) {\n  .edu-hero {\n    grid-template-columns: 1fr;\n    padding: 75px 6%;\n  }\n\n  .edu-hero h1 {\n    font-size: 42px;\n  }\n\n  .edu-goal-grid {\n    grid-template-columns: repeat(2, 1fr);\n  }\n\n  .edu-course-grid {\n    grid-template-columns: repeat(2, 1fr);\n  }\n\n  .edu-step-grid {\n    grid-template-columns: 1fr;\n  }\n}\n\n@media (max-width: 700px) {\n  .edu-hero {\n    padding: 60px 24px;\n    border-radius: 0 0 28px 28px;\n  }\n\n  .edu-hero h1 {\n    font-size: 34px;\n  }\n\n  .edu-hero p {\n    font-size: 15.5px;\n  }\n\n  .edu-hero-card {\n    padding: 26px;\n  }\n\n  .edu-hero-img {\n    width: 90%;\n    height: 230px;\n    margin: -30px auto 45px;\n    border-radius: 22px;\n    border: 5px solid #ffffff;\n  }\n\n  .edu-section {\n    padding: 50px 24px;\n  }\n\n  .edu-section-title h2 {\n    font-size: 28px;\n  }\n\n  .edu-about-box {\n    padding: 26px;\n  }\n\n  .edu-goal-grid,\n  .edu-course-grid,\n  .edu-step-grid {\n    grid-template-columns: 1fr;\n  }\n\n  .edu-course-card {\n    min-height: auto;\n  }\n\n  .edu-hero-buttons {\n    flex-direction: column;\n  }\n\n  .edu-btn-primary,\n  .edu-btn-secondary {\n    text-align: center;\n    width: 100%;\n  }\n}\n\n\n</style>\n\n<div class=\"edu-home\">\n\n  <section class=\"edu-hero\">\n    <div class=\"edu-hero-content\">\n      <span class=\"edu-badge\">Learning Management System</span>\n      <h1>Selamat Datang di LMS EduClass</h1>\n      <p>\n        EduClass adalah Learning Management System berbasis WordPress yang dibuat untuk mendukung proses pembelajaran online melalui localhost. LMS ini menyediakan berbagai mata kuliah yang dilengkapi dengan materi, latihan, penugasan, dan presensi pada setiap pertemuan.\n      </p>\n\n      <div class=\"edu-hero-buttons\">\n        <a href=\"/wordpress/courses\" class=\"edu-btn-primary\">Lihat Mata Kuliah</a>\n        <a href=\"#tentang-lms\" class=\"edu-btn-secondary\">Tentang LMS</a>\n      </div>\n    </div>\n\n    <div class=\"edu-hero-card\">\n      <h3>EduClass LMS</h3>\n      <p>Platform pembelajaran digital untuk mahasiswa.</p>\n      <div class=\"edu-mini-list\">\n        <span>Materi</span>\n        <span>Latihan</span>\n        <span>Tugas</span>\n        <span>Presensi</span>\n      </div>\n    </div>\n  </section>\n\n <img src=\"http://localhost/wordpress/wp-content/uploads/2026/06/unlam.jpeg\" class=\"edu-hero-img\" alt=\"Foto LMS\">\n  <section class=\"edu-section\" id=\"tentang-lms\">\n    <div class=\"edu-section-title\">\n      <span>Tentang LMS</span>\n      <h2>Deskripsi LMS EduClass</h2>\n    </div>\n\n    <div class=\"edu-about-box\">\n      <p>\n        Melalui LMS ini, mahasiswa dapat mengakses materi pembelajaran secara terstruktur, mengikuti latihan, mengerjakan tugas, serta mengisi daftar hadir sesuai dengan mata kuliah yang dipilih.\n      </p>\n\n      <p>\n        LMS EduClass dibuat sebagai media pembelajaran digital yang membantu dosen dan mahasiswa dalam proses pembelajaran berbasis teknologi.\n      </p>\n    </div>\n  </section>\n\n  <section class=\"edu-section\">\n    <div class=\"edu-section-title\">\n      <span>Tujuan</span>\n      <h2>Tujuan Pengembangan LMS</h2>\n    </div>\n\n    <div class=\"edu-goal-grid\">\n      <div class=\"edu-goal-card\">\n        <h3>01</h3>\n        <p>Menyediakan media pembelajaran digital yang mudah digunakan.</p>\n      </div>\n\n      <div class=\"edu-goal-card\">\n        <h3>02</h3>\n        <p>Memudahkan mahasiswa mengakses materi kuliah secara online.</p>\n      </div>\n\n      <div class=\"edu-goal-card\">\n        <h3>03</h3>\n        <p>Membantu dosen mengelola materi, tugas, latihan, dan presensi.</p>\n      </div>\n\n      <div class=\"edu-goal-card\">\n        <h3>04</h3>\n        <p>Melatih penggunaan WordPress sebagai platform e-learning.</p>\n      </div>\n    </div>\n  </section>\n\n  <section class=\"edu-section\" id=\"daftar-matkul\">\n  <div class=\"edu-section-title\">\n    <span>Daftar Mata Kuliah</span>\n    <h2>Mata Kuliah yang Tersedia</h2>\n  </div>\n\n  <div class=\"edu-course-grid\">\n\n    <div class=\"edu-course-card\">\n      <div class=\"edu-course-icon\">💼</div>\n      <h3>Kewirausahaan</h3>\n      <p>Mempelajari konsep usaha, peluang bisnis, perencanaan usaha, pemasaran, dan pengelolaan keuangan.</p>\n      <a href=\"courses/kewirausahaan/\">Lihat Materi</a>\n    </div>\n\n    <div class=\"edu-course-card\">\n      <div class=\"edu-course-icon\">🇮🇩</div>\n      <h3>Pancasila</h3>\n      <p>Mempelajari nilai-nilai Pancasila sebagai dasar negara dan penerapannya dalam kehidupan sehari-hari.</p>\n      <a href=\"courses/pancasila/\">Lihat Materi</a>\n    </div>\n\n    <div class=\"edu-course-card\">\n      <div class=\"edu-course-icon\">📐</div>\n      <h3>Matematika Dasar</h3>\n      <p>Mempelajari konsep dasar matematika seperti bilangan, aljabar, fungsi, geometri, dan statistika.</p>\n      <a href=\"courses/matematika-dasar/\">Lihat Materi</a>\n    </div>\n\n    <div class=\"edu-course-card\">\n      <div class=\"edu-course-icon\">👨‍🏫</div>\n      <h3>Profesi Kependidikan</h3>\n      <p>Mempelajari peran, tugas, kompetensi, dan etika seorang pendidik profesional.</p>\n      <a href=\"courses/profesi-kependidikan/\">Lihat Materi</a>\n    </div>\n\n    <div class=\"edu-course-card\">\n      <div class=\"edu-course-icon\">🏫</div>\n      <h3>Manajemen dan Administrasi Sekolah</h3>\n      <p>Mempelajari pengelolaan sekolah, administrasi pendidikan, kepemimpinan, dan layanan pendidikan.</p>\n      <a href=\"courses/manajemen-dan-administrasi-sekolah/\">Lihat Materi</a>\n    </div>\n\n  </div>\n</section>\n\n  <section class=\"edu-section\">\n    <div class=\"edu-section-title\">\n      <span>Alur Penggunaan</span>\n      <h2>Cara Menggunakan LMS</h2>\n    </div>\n\n    <div class=\"edu-step-grid\">\n      <div class=\"edu-step-card\">\n        <span>1</span>\n        <h3>Pilih Mata Kuliah</h3>\n        <p>Mahasiswa memilih mata kuliah yang tersedia pada LMS.</p>\n      </div>\n\n      <div class=\"edu-step-card\">\n        <span>2</span>\n        <h3>Pelajari Materi</h3>\n        <p>Mahasiswa membaca materi, mengerjakan latihan, dan memahami isi pembelajaran.</p>\n      </div>\n\n      <div class=\"edu-step-card\">\n        <span>3</span>\n        <h3>Kumpulkan Tugas</h3>\n        <p>Mahasiswa mengisi presensi dan mengumpulkan tugas sesuai pertemuan.</p>\n      </div>\n    </div>\n  </section>\n\n</div>\n<!-- /wp:html -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->','Beranda','','inherit','closed','closed','','1052-revision-v1','','','2026-06-16 15:49:16','2026-06-16 15:49:16','',1052,'http://localhost/wordpress/?p=1285',0,'revision','',0),(1404,2,'2026-06-16 21:12:34','2026-06-16 13:12:34','<p>Mata kuliah Kewirausahaan membahas konsep dasar dalam membangun dan mengembangkan usaha secara kreatif, inovatif, dan mandiri. Mahasiswa akan mempelajari cara menemukan peluang usaha, menyusun rencana bisnis, menentukan strategi pemasaran, mengelola keuangan, serta mengevaluasi kelayakan usaha. Mata kuliah ini bertujuan membentuk mahasiswa agar memiliki jiwa wirausaha, berani mengambil risiko, mampu berpikir kreatif, dan siap menciptakan peluang usaha di masyarakat.</p><h2 data-section-id=\"1qf9anr\" data-start=\"409\" data-end=\"433\">Capaian Pembelajaran</h2><p data-start=\"434\" data-end=\"485\">Setelah mengikuti mata kuliah ini, mahasiswa mampu:</p><ol data-start=\"486\" data-end=\"688\"><li data-section-id=\"ydwkys\" data-start=\"486\" data-end=\"524\"><p data-start=\"488\" data-end=\"524\">Memahami konsep dasar kewirausahaan.</p></li><li data-section-id=\"1wsgthl\" data-start=\"525\" data-end=\"558\"><p data-start=\"527\" data-end=\"558\">Mengidentifikasi peluang usaha.</p></li><li data-section-id=\"1b8tkrj\" data-start=\"559\" data-end=\"595\"><p data-start=\"561\" data-end=\"595\">Menyusun rencana bisnis sederhana.</p></li><li data-section-id=\"gilarj\" data-start=\"596\" data-end=\"628\"><p data-start=\"598\" data-end=\"628\">Menerapkan strategi pemasaran.</p></li><li data-section-id=\"19k2fem\" data-start=\"629\" data-end=\"656\"><p data-start=\"631\" data-end=\"656\">Mengelola keuangan usaha.</p></li><li data-section-id=\"1ti47l2\" data-start=\"657\" data-end=\"688\"><p data-start=\"659\" data-end=\"688\">Mengevaluasi kelayakan usaha.</p></li></ol>','Kewirausahaan','','trash','closed','closed','','kewirausahaan-2','','','2026-06-16 21:12:34','2026-06-16 13:12:34','',0,'http://localhost/wordpress/?post_type=courses&amp;p=965',0,'courses','',0),(1407,2,'2026-06-16 21:19:58','2026-06-16 13:19:58','<p>Mata kuliah Pancasila membahas nilai-nilai dasar Pancasila sebagai ideologi negara, dasar negara, dan pandangan hidup bangsa Indonesia. Mahasiswa akan mempelajari sejarah lahirnya Pancasila, makna setiap sila, serta penerapannya dalam kehidupan bermasyarakat, berbangsa, dan bernegara. Mata kuliah ini bertujuan membentuk mahasiswa yang memiliki sikap nasionalisme, toleransi, tanggung jawab, dan mampu menerapkan nilai Pancasila dalam kehidupan sehari-hari.</p><h2 data-section-id=\"1qf9anr\" data-start=\"1102\" data-end=\"1126\">Capaian Pembelajaran</h2><p data-start=\"1127\" data-end=\"1178\">Setelah mengikuti mata kuliah ini, mahasiswa mampu:</p><ol data-start=\"1179\" data-end=\"1383\"><li data-section-id=\"enqeej\" data-start=\"1179\" data-end=\"1217\"><p data-start=\"1181\" data-end=\"1217\">Memahami sejarah lahirnya Pancasila.</p></li><li data-section-id=\"ds3m1e\" data-start=\"1218\" data-end=\"1254\"><p data-start=\"1220\" data-end=\"1254\">Menjelaskan nilai-nilai Pancasila.</p></li><li data-section-id=\"1bgx7p6\" data-start=\"1255\" data-end=\"1309\"><p data-start=\"1257\" data-end=\"1309\">Mengimplementasikan nilai Pancasila dalam kehidupan.</p></li><li data-section-id=\"1m3expr\" data-start=\"1310\" data-end=\"1349\"><p data-start=\"1312\" data-end=\"1349\">Menganalisis permasalahan kebangsaan.</p></li><li data-section-id=\"2px8ug\" data-start=\"1350\" data-end=\"1383\"><p data-start=\"1352\" data-end=\"1383\">Menumbuhkan sikap nasionalisme.</p></li></ol>','Pancasila','','trash','closed','closed','','pancasila-2','','','2026-06-16 21:19:58','2026-06-16 13:19:58','',0,'http://localhost/wordpress/?post_type=courses&amp;p=1009',0,'courses','',0),(1408,2,'2026-06-16 21:27:31','2026-06-16 13:27:31','<p>Mata kuliah Matematika Dasar membahas konsep-konsep dasar matematika yang digunakan untuk mendukung pemahaman dalam berbagai bidang ilmu. Materi yang dipelajari meliputi bilangan, aljabar, persamaan, fungsi, geometri, dan statistika dasar. Mata kuliah ini bertujuan melatih kemampuan berpikir logis, sistematis, analitis, serta membantu mahasiswa dalam menyelesaikan masalah sederhana menggunakan konsep matematika.</p><h3 data-section-id=\"1qf9anr\" data-start=\"1842\" data-end=\"1866\">Capaian Pembelajaran</h3><p data-start=\"1867\" data-end=\"1918\">Setelah mengikuti mata kuliah ini, mahasiswa mampu:</p><ol data-start=\"1919\" data-end=\"2126\"><li data-section-id=\"4w48g0\" data-start=\"1919\" data-end=\"1954\"><p data-start=\"1921\" data-end=\"1954\">Memahami konsep dasar matematika.</p></li><li data-section-id=\"1tbve32\" data-start=\"1955\" data-end=\"1987\"><p data-start=\"1957\" data-end=\"1987\">Menyelesaikan operasi aljabar.</p></li><li data-section-id=\"yjan9f\" data-start=\"1988\" data-end=\"2023\"><p data-start=\"1990\" data-end=\"2023\">Menggunakan persamaan dan fungsi.</p></li><li data-section-id=\"7boawm\" data-start=\"2024\" data-end=\"2066\"><p data-start=\"2026\" data-end=\"2066\">Memecahkan masalah matematika sederhana.</p></li><li data-section-id=\"17qiqon\" data-start=\"2067\" data-end=\"2126\"><p data-start=\"2069\" data-end=\"2126\">Menerapkan konsep matematika dalam kehidupan sehari-hari.</p></li></ol>','Matematika Dasar','','trash','closed','closed','','matematika-dasar-2','','','2026-06-16 21:27:31','2026-06-16 13:27:31','',0,'http://localhost/wordpress/?post_type=courses&amp;p=1016',0,'courses','',0),(1409,2,'2026-06-16 20:40:46','2026-06-16 12:40:46','<p>Mata kuliah Profesi Kependidikan membahas peran, tugas, tanggung jawab, dan kompetensi yang harus dimiliki oleh seorang pendidik profesional. Mahasiswa akan mempelajari konsep profesi guru, kode etik, hak dan kewajiban guru, serta tantangan profesi kependidikan di era digital. Mata kuliah ini bertujuan membentuk calon pendidik yang profesional, beretika, bertanggung jawab, dan mampu beradaptasi dengan perkembangan dunia pendidikan.</p><h3 data-section-id=\"1qf9anr\" data-start=\"2482\" data-end=\"2506\">Capaian Pembelajaran</h3><p data-start=\"2507\" data-end=\"2558\">Setelah mengikuti mata kuliah ini, mahasiswa mampu:</p><ol data-start=\"2559\" data-end=\"2727\"><li data-section-id=\"1imprcf\" data-start=\"2559\" data-end=\"2587\"><p data-start=\"2561\" data-end=\"2587\">Memahami profesi keguruan.</p></li><li data-section-id=\"lrshfd\" data-start=\"2588\" data-end=\"2618\"><p data-start=\"2590\" data-end=\"2618\">Menjelaskan kompetensi guru.</p></li><li data-section-id=\"cl2czk\" data-start=\"2619\" data-end=\"2650\"><p data-start=\"2621\" data-end=\"2650\">Menerapkan kode etik profesi.</p></li><li data-section-id=\"11sj8rp\" data-start=\"2651\" data-end=\"2685\"><p data-start=\"2653\" data-end=\"2685\">Memahami hak dan kewajiban guru.</p></li><li data-section-id=\"1706ra3\" data-start=\"2686\" data-end=\"2727\"><p data-start=\"2688\" data-end=\"2727\">Mengembangkan profesionalisme pendidik.</p></li></ol>','Profesi Kependidikan','','trash','closed','closed','','profesi-kependidikan-2','','','2026-06-16 20:40:46','2026-06-16 12:40:46','',0,'http://localhost/wordpress/?post_type=courses&amp;p=1017',0,'courses','',0),(1410,2,'2026-06-16 21:41:55','2026-06-16 13:41:55','<p>Mata kuliah Manajemen dan Administrasi Sekolah membahas cara mengelola sekolah secara efektif dan terstruktur. Mahasiswa akan mempelajari fungsi manajemen, administrasi sekolah, perencanaan program, pengelolaan sumber daya, administrasi kurikulum, kesiswaan, serta evaluasi kegiatan sekolah. Mata kuliah ini bertujuan agar mahasiswa mampu memahami proses pengelolaan lembaga pendidikan secara baik, tertib, dan sesuai kebutuhan sekolah.</p><h3 data-section-id=\"1qf9anr\" data-start=\"3194\" data-end=\"3218\">Capaian Pembelajaran</h3><p data-start=\"3219\" data-end=\"3270\">Setelah mengikuti mata kuliah ini, mahasiswa mampu:</p><ol data-start=\"3271\" data-end=\"3463\"><li data-section-id=\"zl5t4u\" data-start=\"3271\" data-end=\"3307\"><p data-start=\"3273\" data-end=\"3307\">Memahami konsep manajemen sekolah.</p></li><li data-section-id=\"7asa0a\" data-start=\"3308\" data-end=\"3350\"><p data-start=\"3310\" data-end=\"3350\">Menjelaskan fungsi administrasi sekolah.</p></li><li data-section-id=\"1eyh88g\" data-start=\"3351\" data-end=\"3386\"><p data-start=\"3353\" data-end=\"3386\">Mengelola sumber daya pendidikan.</p></li><li data-section-id=\"12fctzb\" data-start=\"3387\" data-end=\"3414\"><p data-start=\"3389\" data-end=\"3414\">Menyusun program sekolah.</p></li><li data-section-id=\"5yiwix\" data-start=\"3415\" data-end=\"3463\"><p data-start=\"3417\" data-end=\"3463\">Mengevaluasi pelaksanaan administrasi sekolah.</p></li></ol>','Manajemen dan Administrasi Sekolah','','trash','closed','closed','','manajemen-dan-administrasi-sekolah-2','','','2026-06-16 21:41:55','2026-06-16 13:41:55','',0,'http://localhost/wordpress/?post_type=courses&amp;p=1018',0,'courses','',0),(1536,2,'2026-06-16 12:28:20','2026-06-16 12:28:20','','profesi','','inherit','open','closed','','profesi-2','','','2026-06-16 12:28:20','2026-06-16 12:28:20','',0,'http://localhost/wordpress/wp-content/uploads/2026/06/profesi-1.jpeg',0,'attachment','image/jpeg',0);
