--
-- Table structure for table `wp_tutor_scheduler`
--

DROP TABLE IF EXISTS `wp_tutor_scheduler`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `wp_tutor_scheduler` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `type` varchar(50) COLLATE utf8mb4_unicode_520_ci NOT NULL COMMENT 'Type of schedule, e.g., gift, email, reminder',
  `reference_id` varchar(255) COLLATE utf8mb4_unicode_520_ci NOT NULL COMMENT 'Unique reference id, token, etc',
  `scheduled_at_gmt` datetime NOT NULL COMMENT 'When the action should be executed',
  `status` varchar(255) COLLATE utf8mb4_unicode_520_ci NOT NULL DEFAULT 'processing',
  `payload` longtext COLLATE utf8mb4_unicode_520_ci,
  `created_at_gmt` datetime DEFAULT NULL,
  `updated_at_gmt` datetime DEFAULT NULL,
  `scheduled_by` bigint unsigned DEFAULT NULL COMMENT 'User who scheduled the action',
  `scheduled_for` bigint unsigned DEFAULT NULL COMMENT 'Target user of the scheduled action',
  PRIMARY KEY (`id`),
  KEY `idx_context_status` (`type`,`status`),
  KEY `idx_status` (`status`),
  KEY `idx_scheduled_at_gmt` (`scheduled_at_gmt`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_520_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

